option.value:
/* =========================================================
   Home Automation Server – Main Stylesheet
   ========================================================= */

:root {
    --bg: #0f0f12;
    --surface: #1a1a22;
    --surface2: #24242f;
    --border: #2e2e3e;
    --accent: #7c6af7;
    --accent-hover: #9d8fff;
    --success: #34d399;
    --danger: #f87171;
    --warning: #fbbf24;
    --text: #e2e2f0;
    --text-muted: #8888aa;
    --mono-font: "JetBrains Mono", "Fira Code", "Cascadia Code", monospace;
    --sans-font: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    --radius: 10px;
    --radius-sm: 6px;
    --shadow: 0 4px 24px rgba(0, 0, 0, 0.4);
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { font-size: 16px; }

body {
    background: var(--bg);
    color: var(--text);
    font-family: var(--sans-font);
    line-height: 1.6;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

/* ── Header ── */
.site-header {
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    padding: 0 2rem;
    position: sticky;
    top: 0;
    z-index: 100;
}

.header-inner {
    max-width: 1200px;
    margin: 0 auto;
    height: 60px;
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.logo {
    font-size: 1.25rem;
    font-weight: 700;
    color: var(--text);
    text-decoration: none;
    letter-spacing: -0.5px;
}

nav { display: flex; gap: 1.5rem; }

nav a {
    color: var(--text-muted);
    text-decoration: none;
    font-size: 0.9rem;
    transition: color 0.15s;
}

nav a:hover { color: var(--accent-hover); }

.header-subnav {
    border-top: 1px solid var(--border);
}

.header-subnav-inner {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0.45rem 0 0.55rem;
    display: flex;
    gap: 1rem;
    overflow-x: auto;
    white-space: nowrap;
}

.header-subnav-link {
    color: var(--text-muted);
    text-decoration: none;
    font-size: 0.82rem;
    padding: 0.12rem 0;
    border-bottom: 2px solid transparent;
    transition: color 0.15s, border-color 0.15s;
}

.header-subnav-link:hover {
    color: var(--accent-hover);
}

.header-subnav-link.is-active {
    color: var(--text);
    border-color: var(--accent);
}

/* ── Main container ── */
.container {
    max-width: 1200px;
    margin: 2rem auto;
    padding: 0 2rem;
    flex: 1;
    width: 100%;
}

/* ── Footer ── */
.site-footer {
    text-align: center;
    padding: 1.5rem;
    font-size: 0.8rem;
    color: var(--text-muted);
    border-top: 1px solid var(--border);
    margin-top: 3rem;
}

/* ── Page header ── */
.page-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 1.5rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid var(--border);
}

.page-header h1 { font-size: 1.75rem; font-weight: 700; }

/* ── Hero (index) ── */
.hero { margin-bottom: 2.5rem; }
.hero h1 { font-size: 2.2rem; font-weight: 800; margin-bottom: 0.5rem; }
.subtitle { color: var(--text-muted); font-size: 1.1rem; }

/* ── Card grid ── */
.card-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 1.25rem;
    margin-bottom: 2rem;
}

.card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 1.5rem;
    text-decoration: none;
    color: var(--text);
    transition: border-color 0.15s, transform 0.15s;
    display: block;
}

.card:hover {
    border-color: var(--accent);
    transform: translateY(-2px);
}

.card-icon { font-size: 2rem; display: block; margin-bottom: 0.75rem; }
.card h2 { font-size: 1.1rem; margin-bottom: 0.25rem; }
.card p { font-size: 0.85rem; color: var(--text-muted); }

/* ── Card form ── */
.card-form {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 1.5rem;
    margin-bottom: 1.5rem;
}

.card-form h2 { margin-bottom: 1rem; font-size: 1.15rem; }

/* ── Forms ── */
.form {
    display: flex;
    flex-direction: column;
    gap: 0.85rem;
}

.form label {
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
    font-size: 0.875rem;
    color: var(--text-muted);
}

.form input,
.form select,
.form textarea {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    color: var(--text);
    font-size: 0.95rem;
    font-family: var(--sans-font);
    padding: 0.55rem 0.75rem;
    transition: border-color 0.15s;
    width: 100%;
}

.form input:focus,
.form select:focus,
.form textarea:focus {
    outline: none;
    border-color: var(--accent);
}

/* ── Buttons ── */
.btn {
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    border: none;
    border-radius: var(--radius-sm);
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
    padding: 0.55rem 1.1rem;
    transition: opacity 0.15s, transform 0.1s;
    text-decoration: none;
}

.btn:hover { opacity: 0.88; transform: translateY(-1px); }
.btn:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

.btn-primary  { background: var(--accent);  color: #fff; }
.btn-success  { background: var(--success); color: #000; }
.btn-danger   { background: var(--danger);  color: #000; }
.btn-secondary{ background: var(--surface2); color: var(--text); border: 1px solid var(--border); }

.btn-sm { font-size: 0.8rem; padding: 0.3rem 0.7rem; }

/* ── Tables ── */
.data-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.data-table th,
.data-table td {
    text-align: left;
    padding: 0.65rem 1rem;
    border-bottom: 1px solid var(--border);
}

.data-table th {
    background: var(--surface2);
    color: var(--text-muted);
    font-weight: 600;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.data-table tr:hover td { background: var(--surface2); }

/* ── Device cards (mobile layout) ── */
.device-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 1rem;
    margin-bottom: 0.75rem;
}

.device-card-header {
    margin-bottom: 0.75rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid var(--border);
}

.device-card-header h3 {
    margin: 0;
    font-size: 1rem;
    color: var(--text);
}

.device-card-body {
    margin-bottom: 0.75rem;
}

.device-info-row {
    display: flex;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
    align-items: flex-start;
}

.device-label {
    font-size: 0.8rem;
    color: var(--text-muted);
    font-weight: 600;
    min-width: 70px;
}

.device-value {
    font-size: 0.85rem;
    color: var(--text);
    word-break: break-all;
    flex: 1;
}

.device-badges {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

.device-card-actions {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

/* ── Flow cards (mobile layout) ── */
.flow-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 1rem;
    margin-bottom: 0.75rem;
}

.flow-card-header {
    margin-bottom: 0.75rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid var(--border);
}

.flow-card-header h3 {
    margin: 0;
    font-size: 1rem;
    color: var(--text);
}

.flow-card-body {
    margin-bottom: 0.75rem;
}

.flow-info-row {
    display: flex;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
    align-items: flex-start;
}

.flow-label {
    font-size: 0.8rem;
    color: var(--text-muted);
    font-weight: 600;
    min-width: 70px;
}

.flow-value {
    font-size: 0.85rem;
    color: var(--text);
    flex: 1;
}

.flow-badges {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

.flow-card-actions {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

/* Device cards for mobile */
.devices-card-grid { display: none; }
.flows-card-grid { display: none; }
.data-table-desktop { display: table; }

/* ── Badges ── */
.badge {
    display: inline-block;
    padding: 0.2rem 0.55rem;
    border-radius: 999px;
    font-size: 0.75rem;
    font-weight: 600;
    background: var(--surface2);
    color: var(--text-muted);
    border: 1px solid var(--border);
}

.badge-trigger { background: rgba(124,106,247,0.2); color: var(--accent-hover); border-color: var(--accent); }
.badge-action  { background: rgba(52,211,153,0.15); color: var(--success); border-color: var(--success); }

/* ── Notices ── */
.notice {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.85rem 1rem;
    font-size: 0.9rem;
    color: var(--text-muted);
    margin: 0.75rem 0;
}

.notice a { color: var(--accent-hover); }

/* ── Collapsible ── */
.collapsible {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    margin-bottom: 1.5rem;
}

.collapsible summary {
    cursor: pointer;
    padding: 1rem 1.25rem;
    font-weight: 600;
    user-select: none;
    list-style: none;
}

.collapsible summary::-webkit-details-marker { display: none; }

.collapsible .form,
.collapsible > form {
    padding: 0 1.25rem 1.25rem;
}

/* ── Scan card ── */
.scan-card {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.85rem 1rem;
    margin-bottom: 0.6rem;
    display: flex;
    align-items: center;
    gap: 0.75rem;
    flex-wrap: wrap;
}

/* ── Credential block ── */
.credential-block {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 1rem 1.25rem;
    margin-bottom: 1rem;
}

.credential-block h3 {
    margin-bottom: 0.75rem;
    font-size: 1rem;
    color: var(--text-muted);
}

/* ── Utility ── */
.mono { font-family: var(--mono-font); font-size: 0.82rem; }
.truncate { max-width: 280px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.hidden { display: none !important; }

.webhook-url {
    font-size: 0.75rem;
    color: var(--text-muted);
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 0.15rem 0.45rem;
}

/* ── Controls page ── */
.controls-error-banner {
    position: fixed;
    top: 78px;
    left: 50%;
    transform: translateX(-50%);
    width: min(920px, calc(100vw - 2rem));
    z-index: 1200;
    border-color: var(--danger);
    color: var(--danger);
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.75rem;
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.35);
}

.controls-direction-grid {
    display: grid;
    grid-template-columns: repeat(3, minmax(70px, 90px));
    gap: 0.5rem;
    align-items: center;
    justify-content: start;
}

.controls-button-row {
    display: flex;
    gap: 0.6rem;
    flex-wrap: wrap;
}

.controls-power-state-row {
    margin-top: 0.75rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.controls-apps-header {
    margin-bottom: 1rem;
}

.controls-apps-results {
    margin-top: 1rem;
}

.controls-provider-stack {
    display: grid;
    gap: 2rem;
}

.controls-provider-section {
    display: grid;
    gap: 1rem;
}

.controls-provider-header {
    margin-bottom: 0;
}

.controls-provider-header h2 {
    margin-bottom: 0.25rem;
    font-size: 1.2rem;
}

.automation-recorder {
    border: 1px solid var(--border);
    border-radius: var(--radius);
    background: var(--surface);
    padding: 1rem;
}

.automation-recorder-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.75rem;
    margin-bottom: 0.35rem;
}

.automation-recorder-header h3 {
    margin: 0;
    font-size: 1rem;
}

.automation-recorder-controls {
    display: grid;
    gap: 0.7rem;
}

.recording-pulse-overlay {
    position: fixed;
    right: 1rem;
    bottom: 1rem;
    z-index: 40;
    display: inline-flex;
    align-items: center;
    gap: 0.45rem;
    background: var(--surface);
    border: 1px solid var(--danger);
    border-radius: 999px;
    padding: 0.4rem 0.7rem;
    color: var(--danger);
    font-size: 0.8rem;
    font-weight: 600;
    box-shadow: 0 6px 20px color-mix(in srgb, var(--danger) 22%, transparent);
}

.recording-pulse-dot {
    width: 0.55rem;
    height: 0.55rem;
    border-radius: 999px;
    background: var(--danger);
    animation: recorder-pulse 1.2s ease-in-out infinite;
}

.recording-pulse-overlay.is-flash {
    animation: recorder-flash 0.45s ease;
}

@keyframes recorder-pulse {
    0%, 100% { opacity: 1; transform: scale(1); }
    50% { opacity: 0.45; transform: scale(0.85); }
}

@keyframes recorder-flash {
    0% { box-shadow: 0 0 0 0 color-mix(in srgb, var(--danger) 40%, transparent); }
    100% { box-shadow: 0 0 0 14px color-mix(in srgb, var(--danger) 0%, transparent); }
}

.cp-device-selector {
    display: flex;
    justify-content: space-between;
    align-items: end;
    gap: 1rem;
    flex-wrap: wrap;
}

.cp-label {
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
    font-size: 0.875rem;
    color: var(--text-muted);
    flex: 1 1 280px;
}

.cp-select,
.cp-input {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    color: var(--text);
    font-size: 0.95rem;
    font-family: var(--sans-font);
    padding: 0.55rem 0.75rem;
    width: 100%;
}

.cp-select:focus,
.cp-input:focus {
    outline: none;
    border-color: var(--accent);
}

.cp-power-row {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.cp-device-summary {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.cp-device-title {
    margin: 0;
    font-size: 1.25rem;
}

.cp-device-meta {
    color: var(--text-muted);
}

.cp-power-label {
    font-size: 0.85rem;
    color: var(--text-muted);
}

.cp-badge {
    min-width: 88px;
    text-align: center;
}

.cp-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
    gap: 1rem;
}

.cp-panel {
    margin-bottom: 0;
}

.cp-panel-wide {
    grid-column: 1 / -1;
}

.cp-panel-title {
    margin-bottom: 0.85rem;
    font-size: 1rem;
}

.cp-panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.75rem;
}

.cp-dpad {
    display: grid;
    grid-template-columns: repeat(3, minmax(60px, 76px));
    gap: 0.5rem;
    justify-content: center;
    align-items: center;
}

.cp-btn-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
    gap: 0.55rem;
}

.cp-btn {
    width: 100%;
    justify-content: center;
}

.cp-dpad-center {
    min-height: 52px;
}

.cp-input-row {
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.cp-input-row .btn {
    flex: 0 0 auto;
}

.cp-input-row .cp-input {
    flex: 1 1 260px;
}

.cp-apps-results {
    margin-top: 0.85rem;
}

.remote-page {
    display: grid;
    gap: 1rem;
}

.remote-layout {
    display: grid;
    gap: 1.25rem;
    align-items: start;
}

.remote-layout-apple {
    grid-template-columns: minmax(260px, 320px) 1fr;
}

.remote-layout-samsung {
    grid-template-columns: minmax(280px, 340px) 1fr;
}

.remote-shell {
    background: linear-gradient(180deg, #3a3a44 0%, #23232b 55%, #17171d 100%);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 40px;
    padding: 1.2rem 1rem 1.4rem;
    box-shadow: inset 0 1px 0 rgba(255,255,255,0.12), 0 22px 40px rgba(0,0,0,0.35);
    display: grid;
    gap: 0.9rem;
    justify-items: center;
}

.remote-shell-apple {
    min-height: 720px;
    max-width: 320px;
}

.remote-shell-samsung {
    min-height: 720px;
    max-width: 340px;
    border-radius: 36px;
}

.remote-shell-top {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.remote-shell-top-samsung {
    justify-content: flex-end;
}

.remote-icon-btn {
    width: 42px;
    height: 42px;
    border-radius: 999px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.08);
    color: var(--text);
    cursor: pointer;
    font-size: 1rem;
    transition: transform 0.1s, background 0.15s, border-color 0.15s;
}

.remote-icon-btn:hover {
    transform: translateY(-1px);
    background: rgba(255,255,255,0.14);
}

.remote-icon-btn-danger {
    background: rgba(248, 113, 113, 0.18);
    border-color: rgba(248, 113, 113, 0.55);
    color: #fecaca;
}

.remote-touchpad {
    position: relative;
    width: 220px;
    height: 220px;
    border-radius: 50%;
    background: radial-gradient(circle at 35% 30%, rgba(255,255,255,0.12), rgba(255,255,255,0.02) 62%, rgba(0,0,0,0.28) 100%);
    border: 1px solid rgba(255,255,255,0.12);
    box-shadow: inset 0 6px 16px rgba(255,255,255,0.05), inset 0 -10px 18px rgba(0,0,0,0.25);
}

.remote-touchpad-samsung {
    width: 210px;
    height: 210px;
}

.remote-direction,
.remote-touchpad-center {
    position: absolute;
    border: none;
    background: transparent;
    color: var(--text);
    cursor: pointer;
}

.remote-touchpad-center {
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 86px;
    height: 86px;
    border-radius: 50%;
    background: rgba(255,255,255,0.09);
    border: 1px solid rgba(255,255,255,0.12);
    font-weight: 700;
    letter-spacing: 0.03em;
}

.remote-touchpad-center-samsung {
    font-size: 0.8rem;
}

.remote-direction-up {
    top: 18px;
    left: 50%;
    transform: translateX(-50%);
}

.remote-direction-left {
    top: 50%;
    left: 18px;
    transform: translateY(-50%);
}

.remote-direction-right {
    top: 50%;
    right: 18px;
    transform: translateY(-50%);
}

.remote-direction-down {
    bottom: 18px;
    left: 50%;
    transform: translateX(-50%);
}

.remote-pill-row {
    width: 100%;
    display: grid;
    gap: 0.55rem;
}

.remote-pill-row-split {
    grid-template-columns: repeat(2, 1fr);
}

.remote-pill-btn {
    min-height: 48px;
    border-radius: 999px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.08);
    color: var(--text);
    cursor: pointer;
    font-weight: 600;
}

.remote-media-cluster {
    width: 100%;
    display: grid;
    grid-template-columns: 52px 1fr 52px;
    gap: 0.65rem;
    align-items: center;
}

.remote-play-btn,
.remote-small-btn {
    min-height: 54px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.08);
    color: var(--text);
    cursor: pointer;
}

.remote-play-btn {
    border-radius: 999px;
    font-size: 1.1rem;
}

.remote-small-btn {
    border-radius: 18px;
}

.remote-rocker-group {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 0.8rem;
}

.remote-rocker {
    background: rgba(255,255,255,0.06);
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 28px;
    display: grid;
    justify-items: center;
    overflow: hidden;
}

.remote-rocker-btn {
    width: 100%;
    min-height: 56px;
    border: none;
    background: transparent;
    color: var(--text);
    cursor: pointer;
    font-size: 1.2rem;
}

.remote-rocker-label {
    width: 100%;
    text-align: center;
    padding: 0.55rem 0.35rem;
    font-size: 0.82rem;
    color: var(--text-muted);
    border-top: 1px solid rgba(255,255,255,0.08);
    border-bottom: 1px solid rgba(255,255,255,0.08);
}

.remote-companion-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
    gap: 1rem;
}

.remote-card {
    margin-bottom: 0;
}

.remote-card-wide {
    grid-column: 1 / -1;
}

/* ── Samsung-specific remote buttons ── */

.samsung-top-row {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.5rem;
}

/* Input switching row inside the remote shell */
.samsung-input-row {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 0.4rem;
}

.samsung-input-row-secondary {
    grid-template-columns: repeat(3, 1fr);
    opacity: 0.72;
}

.samsung-input-btn {
    min-height: 38px;
    border-radius: var(--radius-sm);
    border: 1px solid rgba(255,255,255,0.14);
    background: rgba(255,255,255,0.06);
    color: var(--text);
    cursor: pointer;
    font-size: 0.78rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    transition: background 0.15s, border-color 0.15s;
}

.samsung-input-btn:hover {
    background: rgba(124,106,247,0.22);
    border-color: rgba(124,106,247,0.55);
    opacity: 1;
}

.samsung-input-btn-primary {
    background: rgba(124,106,247,0.18);
    border-color: rgba(124,106,247,0.4);
    opacity: 1;
}

/* Companion card inputs grid */
.samsung-inputs-companion-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(110px, 1fr));
    gap: 0.5rem;
    margin: 0.5rem 0 0.75rem;
}

.samsung-input-companion-btn {
    min-height: 46px;
    border-radius: var(--radius-sm);
    border: 1px solid var(--border);
    background: var(--surface2);
    color: var(--text);
    cursor: pointer;
    font-size: 0.85rem;
    font-weight: 600;
    transition: background 0.15s, border-color 0.15s, transform 0.1s;
}

.samsung-input-companion-btn:hover {
    background: rgba(124,106,247,0.18);
    border-color: var(--accent);
    transform: translateY(-1px);
}

.samsung-input-companion-primary {
    background: rgba(124,106,247,0.14);
    border-color: rgba(124,106,247,0.45);
}

.samsung-input-tier-label {
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--text-muted);
    margin-top: 0.6rem;
    margin-bottom: 0.25rem;
}

.samsung-input-tier-warning {
    color: #fbbf24;
}

.samsung-source-btn {
    flex: 1;
    min-height: 42px;
    border-radius: 999px;
    border: 1px solid rgba(255,255,255,0.14);
    background: rgba(255,255,255,0.08);
    color: var(--text);
    cursor: pointer;
    font-size: 0.85rem;
    font-weight: 600;
    transition: background 0.15s;
}

.samsung-source-btn:hover { background: rgba(255,255,255,0.15); }

.samsung-sys-row {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 0.45rem;
}

.samsung-sys-btn {
    min-height: 42px;
    border-radius: var(--radius-sm);
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.07);
    color: var(--text);
    cursor: pointer;
    font-size: 1rem;
    transition: background 0.15s;
}

.samsung-sys-btn:hover { background: rgba(255,255,255,0.14); }

.samsung-nav-row {
    width: 100%;
    display: grid;
    grid-template-columns: 1fr 44px 1fr;
    gap: 0.45rem;
    align-items: center;
}

.samsung-nav-btn {
    min-height: 42px;
    border-radius: 999px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.07);
    color: var(--text);
    cursor: pointer;
    font-size: 0.82rem;
    font-weight: 600;
    transition: background 0.15s;
}

.samsung-nav-btn:hover { background: rgba(255,255,255,0.14); }

.samsung-nav-btn-home {
    border-radius: 50%;
    font-size: 1.1rem;
    padding: 0;
}

.samsung-rocker-group {
    grid-template-columns: repeat(3, 1fr);
}

.samsung-media-row {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 0.35rem;
    align-items: center;
}

.samsung-media-btn {
    min-height: 44px;
    border-radius: 10px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.07);
    color: var(--text);
    cursor: pointer;
    font-size: 0.95rem;
    transition: background 0.15s;
}

.samsung-media-btn:hover { background: rgba(255,255,255,0.15); }

.samsung-media-btn-play {
    background: rgba(124,106,247,0.22);
    border-color: rgba(124,106,247,0.55);
}

.samsung-colour-row {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 0.45rem;
}

.samsung-colour-btn {
    min-height: 44px;
    border-radius: 999px;
    border: none;
    color: #fff;
    font-weight: 700;
    cursor: pointer;
    font-size: 0.9rem;
    transition: opacity 0.15s, transform 0.1s;
}

.samsung-colour-btn:hover { opacity: 0.85; transform: translateY(-1px); }
.samsung-colour-red    { background: #e53935; }
.samsung-colour-green  { background: #43a047; }
.samsung-colour-yellow { background: #f9a825; }
.samsung-colour-blue   { background: #1e88e5; }

.samsung-numpad {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 0.5rem;
}

.samsung-num-btn {
    min-height: 52px;
    border-radius: var(--radius-sm);
    border: 1px solid rgba(255,255,255,0.12);
    background: var(--surface2);
    color: var(--text);
    font-size: 1.1rem;
    font-weight: 700;
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
}

.samsung-num-btn:hover {
    background: rgba(124,106,247,0.18);
    border-color: var(--accent);
    transform: translateY(-1px);
}

/* ── Automation builder ── */
.automation-builder {
    display: grid;
    grid-template-columns: minmax(220px, 280px) 1fr;
    gap: 1rem;
    align-items: start;
}

.automation-palette,
.automation-sequence {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.9rem;
}

.automation-palette h3,
.automation-sequence h3 {
    margin-bottom: 0.25rem;
    font-size: 1rem;
}

.palette-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
    border: 1px dashed var(--border);
    border-radius: var(--radius-sm);
    padding: 0.55rem 0.6rem;
    margin-bottom: 0.5rem;
    background: var(--surface);
    cursor: grab;
}

.palette-item:active {
    cursor: grabbing;
}

.sequence-step {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.7rem;
    margin-bottom: 0.6rem;
}

.sequence-step-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.5rem;
}

/* ── Responsive ── */

/* Tablet (640px - 1023px) */
@media (max-width: 1023px) {
    html { font-size: 15px; }
    .container { padding: 0 1.5rem; margin: 1.5rem auto; }
    .card-grid { grid-template-columns: repeat(auto-fill, minmax(160px, 1fr)); }
    .automation-builder { grid-template-columns: 1fr; gap: 1.5rem; }
    .automation-palette { margin-bottom: 0.5rem; }
}

/* Mobile (max 640px) */
@media (max-width: 640px) {
    html { font-size: 14px; }

    /* Header adjustments */
    .site-header { padding: 0 1rem; }
    .header-inner {
        flex-direction: column;
        height: auto;
        padding: 0.75rem 0;
        gap: 0.5rem;
    }
    .logo { font-size: 1.1rem; }

    /* Navigation */
    nav {
        gap: 0.6rem;
        flex-wrap: wrap;
        justify-content: center;
    }
    nav a { font-size: 0.8rem; }
    .header-subnav-inner {
        gap: 0.65rem;
        padding: 0.35rem 0 0.45rem;
    }
    .header-subnav-link {
        font-size: 0.74rem;
    }

    /* Container & spacing */
    .container { padding: 0 1rem; margin: 1rem auto; }
    .page-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 0.75rem;
    }
    .page-header h1 { font-size: 1.5rem; }

    /* Hero */
    .hero h1 { font-size: 1.8rem; }
    .subtitle { font-size: 0.95rem; }

    /* Card grid */
    .card-grid { grid-template-columns: 1fr; }
    .card { padding: 1.25rem; }
    .card-icon { font-size: 1.75rem; }
    .card h2 { font-size: 1rem; }

    /* Forms & inputs (touch-friendly) */
    .form label { font-size: 0.8rem; }
    .form input,
    .form select,
    .form textarea {
        font-size: 1rem; /* Prevent zoom on iOS */
        padding: 0.7rem;
        min-height: 44px; /* Touch target minimum */
    }

    /* Tables – horizontal scroll on mobile */
    .data-table {
        font-size: 0.8rem;
        display: none;
    }
    .data-table-desktop {
        display: none !important;
    }
    .devices-card-grid {
        display: block;
    }
    .flows-card-grid {
        display: block;
    }

    /* Buttons – touch-friendly sizing */
    .btn {
        font-size: 0.85rem;
        padding: 0.65rem 1rem;
        min-height: 44px;
        min-width: 44px;
    }
    .btn-sm { padding: 0.4rem 0.6rem; min-height: 36px; }

    /* Controls */
    .controls-direction-grid {
        grid-template-columns: repeat(3, 1fr);
        gap: 0.4rem;
    }
    .controls-button-row {
        gap: 0.4rem;
        flex-direction: column;
        align-items: stretch;
    }
    .controls-button-row .btn { width: 100%; }
    .controls-power-state-row {
        flex-direction: column;
        align-items: stretch;
        gap: 0.4rem;
    }
    .controls-error-banner {
        width: calc(100vw - 1rem);
        flex-direction: column;
        gap: 0.5rem;
        padding: 0.75rem;
    }
    .controls-provider-header {
        align-items: flex-start;
    }
    .remote-layout-apple,
    .remote-layout-samsung {
        grid-template-columns: 1fr;
    }
    .remote-shell {
        max-width: 100%;
        min-height: auto;
    }
    .remote-touchpad,
    .remote-touchpad-samsung {
        width: 200px;
        height: 200px;
    }
    .cp-device-selector,
    .cp-power-row,
    .cp-panel-header,
    .cp-input-row {
        flex-direction: column;
        align-items: stretch;
    }
    .cp-grid,
    .cp-btn-grid {
        grid-template-columns: 1fr;
    }
    .cp-dpad {
        grid-template-columns: repeat(3, 1fr);
    }
    .remote-companion-grid {
        grid-template-columns: 1fr;
    }
    .remote-rocker-group,
    .samsung-rocker-group,
    .remote-pill-row-split,
    .remote-media-cluster,
    .samsung-media-row,
    .samsung-sys-row {
        grid-template-columns: 1fr;
    }
    .samsung-colour-row {
        grid-template-columns: repeat(4, 1fr);
    }
    .samsung-numpad {
        grid-template-columns: repeat(3, 1fr);
    }
    .samsung-nav-row {
        grid-template-columns: 1fr 44px 1fr;
    }
    .cp-input-row .btn,
    .cp-input-row .cp-input {
        width: 100%;
        flex: 1 1 auto;
    }

    /* Automation builder */
    .automation-builder {
        grid-template-columns: 1fr;
        gap: 1rem;
    }
    .automation-palette,
    .automation-sequence {
        padding: 0.75rem;
    }
    .palette-item {
        flex-direction: column;
        gap: 0.4rem;
    }
    .palette-item span,
    .palette-item button {
        width: 100%;
        text-align: center;
    }
    .sequence-step {
        padding: 0.6rem;
    }
    .sequence-step-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 0.4rem;
    }
    .sequence-step-header strong { word-break: break-word; }

    /* Collapsible */
    .collapsible summary {
        padding: 0.85rem 1rem;
        font-size: 0.95rem;
    }
    .collapsible .form,
    .collapsible > form {
        padding: 0 1rem 1rem;
    }

    /* Badges */
    .badge { font-size: 0.7rem; padding: 0.15rem 0.4rem; }

    /* Utilities */
    .truncate { max-width: 100%; }
    .mono { font-size: 0.75rem; }
    .webhook-url {
        font-size: 0.7rem;
        max-width: 100%;
        overflow-x: auto;
        -webkit-overflow-scrolling: touch;
        display: inline-block;
        word-break: break-all;
        max-height: 2.5rem;
        padding: 0.25rem 0.4rem;
        overflow-y: hidden;
    }

    /* Footer */
    .site-footer { padding: 1rem; font-size: 0.75rem; }
}

/* Ultra-mobile (max 380px) */
@media (max-width: 380px) {
    html { font-size: 13px; }
    .page-header h1 { font-size: 1.3rem; }
    .hero h1 { font-size: 1.5rem; }
    .btn, .btn-sm { padding: 0.6rem 0.8rem; }
    .controls-direction-grid { grid-template-columns: repeat(2, 1fr); }
}

/* ── Delay Slider ──────────────────────────────────────────────────────────── */
.delay-slider-row {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
    padding: 0.75rem 0;
    border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
    margin-bottom: 0.5rem;
}

.delay-slider-label {
    font-size: 0.85rem;
    font-weight: 500;
    color: var(--text-muted);
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.5rem;
}

.delay-slider-display {
    font-variant-numeric: tabular-nums;
    font-weight: 700;
    color: var(--accent);
    min-width: 3.5rem;
    text-align: right;
}

.delay-slider {
    width: 100%;
    accent-color: var(--accent);
    cursor: pointer;
    height: 4px;
}

.delay-slider-ticks {
    display: flex;
    justify-content: space-between;
    font-size: 0.7rem;
    color: var(--text-muted);
    padding: 0 2px;
}

/* ── Clickable flow table rows ─────────────────────────────────────────────── */
.flow-table-row {
    cursor: pointer;
    transition: background 0.12s;
}

.flow-table-row:hover {
    background: color-mix(in srgb, var(--accent) 8%, var(--surface));
}

.flow-table-row.is-previewing {
    background: color-mix(in srgb, var(--accent) 14%, var(--surface));
    outline: 2px solid var(--accent);
    outline-offset: -2px;
}

.flow-card {
    cursor: pointer;
    transition: box-shadow 0.12s, outline 0.12s;
}

.flow-card.is-previewing {
    outline: 2px solid var(--accent);
    box-shadow: 0 0 0 4px color-mix(in srgb, var(--accent) 20%, transparent);
}

/* ── Flow Visualizer Panel ─────────────────────────────────────────────────── */
.flow-visualizer {
    border: 1px solid var(--border);
    border-radius: var(--radius);
    background: var(--surface);
    padding: 1.25rem 1.5rem;
    margin: 1.25rem 0;
    animation: viz-slide-in 0.18s ease;
}

.flow-visualizer.hidden {
    display: none;
}

@keyframes viz-slide-in {
    from { opacity: 0; transform: translateY(-6px); }
    to   { opacity: 1; transform: translateY(0); }
}

.flow-visualizer-header {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.flow-visualizer-header h3 {
    margin: 0;
    font-size: 1rem;
    flex: 1 1 auto;
}

.flow-visualizer-meta {
    font-size: 0.78rem;
    color: var(--text-muted);
    flex: 0 0 auto;
}

.flow-visualizer-steps {
    display: flex;
    flex-wrap: nowrap;
    align-items: center;
    gap: 0.5rem;
    overflow-x: auto;
    padding-bottom: 0.35rem;
}

/* ── Visualizer step nodes ─────────────────────────────────────────────────── */
.viz-step {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    background: color-mix(in srgb, var(--text-muted) 8%, var(--surface));
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.55rem 0.85rem;
    min-width: 220px;
    flex: 0 0 auto;
    transition: border-color 0.2s ease, background 0.2s ease, box-shadow 0.2s ease;
}

.viz-step.is-running {
    border-color: var(--accent);
    box-shadow: 0 0 0 2px color-mix(in srgb, var(--accent) 24%, transparent);
}

.viz-step.is-complete {
    background: color-mix(in srgb, var(--success) 16%, var(--surface));
    border-color: color-mix(in srgb, var(--success) 65%, var(--border));
}

.viz-step.is-error {
    background: color-mix(in srgb, var(--danger) 14%, var(--surface));
    border-color: color-mix(in srgb, var(--danger) 65%, var(--border));
}

.viz-step-icon {
    font-size: 1.1rem;
    width: 1.6rem;
    text-align: center;
    flex-shrink: 0;
}

.viz-step-body {
    display: flex;
    flex-direction: column;
    gap: 0.1rem;
}

.viz-step-num {
    font-size: 0.68rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.04em;
}

.viz-step-label {
    font-size: 0.88rem;
    font-weight: 500;
}

/* Arrow and optional delay between steps */
.viz-link {
    display: flex;
    align-items: center;
    gap: 0.35rem;
    flex: 0 0 auto;
}

.viz-arrow {
    color: var(--text-muted);
    font-size: 1.1rem;
    line-height: 1;
    transition: color 0.2s ease;
}

.viz-link.is-active .viz-arrow,
.viz-link.is-complete .viz-arrow {
    color: var(--success);
}

.viz-link.is-error .viz-arrow {
    color: var(--danger);
}

/* Delay badge between steps */
.viz-delay {
    font-size: 0.72rem;
    color: var(--accent);
    background: color-mix(in srgb, var(--accent) 10%, var(--surface));
    border: 1px solid color-mix(in srgb, var(--accent) 30%, transparent);
    border-radius: 999px;
    padding: 0.15rem 0.6rem;
    margin: 0;
    font-variant-numeric: tabular-nums;
    transition: border-color 0.2s ease, color 0.2s ease;
}

.viz-link.is-active .viz-delay,
.viz-link.is-complete .viz-delay {
    color: var(--success);
    border-color: color-mix(in srgb, var(--success) 50%, transparent);
}

@media (max-width: 640px) {
    .delay-slider-label { flex-direction: column; align-items: flex-start; }
    .delay-slider-display { text-align: left; }
    .flow-visualizer { padding: 0.9rem 1rem; }
    .viz-step { min-width: 180px; }
}

/* =========================================================
   Home Automation Server – Main Stylesheet
   ========================================================= */

:root {
    --bg: #0f0f12;
    --surface: #1a1a22;
    --surface2: #24242f;
    --border: #2e2e3e;
    --accent: #7c6af7;
    --accent-hover: #9d8fff;
    --success: #34d399;
    --danger: #f87171;
    --warning: #fbbf24;
    --text: #e2e2f0;
    --text-muted: #8888aa;
    --mono-font: "JetBrains Mono", "Fira Code", "Cascadia Code", monospace;
    --sans-font: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    --radius: 10px;
    --radius-sm: 6px;
    --shadow: 0 4px 24px rgba(0, 0, 0, 0.4);
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { font-size: 16px; }

body {
    background: var(--bg);
    color: var(--text);
    font-family: var(--sans-font);
    line-height: 1.6;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

/* ── Header ── */
.site-header {
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    padding: 0 2rem;
    position: sticky;
    top: 0;
    z-index: 100;
}

.header-inner {
    max-width: 1200px;
    margin: 0 auto;
    height: 60px;
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.logo {
    font-size: 1.25rem;
    font-weight: 700;
    color: var(--text);
    text-decoration: none;
    letter-spacing: -0.5px;
}

nav { display: flex; gap: 1.5rem; }

nav a {
    color: var(--text-muted);
    text-decoration: none;
    font-size: 0.9rem;
    transition: color 0.15s;
}

nav a:hover { color: var(--accent-hover); }

.header-subnav {
    border-top: 1px solid var(--border);
}

.header-subnav-inner {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0.45rem 0 0.55rem;
    display: flex;
    gap: 1rem;
    overflow-x: auto;
    white-space: nowrap;
}

.header-subnav-link {
    color: var(--text-muted);
    text-decoration: none;
    font-size: 0.82rem;
    padding: 0.12rem 0;
    border-bottom: 2px solid transparent;
    transition: color 0.15s, border-color 0.15s;
}

.header-subnav-link:hover {
    color: var(--accent-hover);
}

.header-subnav-link.is-active {
    color: var(--text);
    border-color: var(--accent);
}

/* ── Main container ── */
.container {
    max-width: 1200px;
    margin: 2rem auto;
    padding: 0 2rem;
    flex: 1;
    width: 100%;
}

/* ── Footer ── */
.site-footer {
    text-align: center;
    padding: 1.5rem;
    font-size: 0.8rem;
    color: var(--text-muted);
    border-top: 1px solid var(--border);
    margin-top: 3rem;
}

/* ── Page header ── */
.page-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 1.5rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid var(--border);
}

.page-header h1 { font-size: 1.75rem; font-weight: 700; }

/* ── Hero (index) ── */
.hero { margin-bottom: 2.5rem; }
.hero h1 { font-size: 2.2rem; font-weight: 800; margin-bottom: 0.5rem; }
.subtitle { color: var(--text-muted); font-size: 1.1rem; }

/* ── Card grid ── */
.card-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 1.25rem;
    margin-bottom: 2rem;
}

.card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 1.5rem;
    text-decoration: none;
    color: var(--text);
    transition: border-color 0.15s, transform 0.15s;
    display: block;
}

.card:hover {
    border-color: var(--accent);
    transform: translateY(-2px);
}

.card-icon { font-size: 2rem; display: block; margin-bottom: 0.75rem; }
.card h2 { font-size: 1.1rem; margin-bottom: 0.25rem; }
.card p { font-size: 0.85rem; color: var(--text-muted); }

/* ── Card form ── */
.card-form {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 1.5rem;
    margin-bottom: 1.5rem;
}

.card-form h2 { margin-bottom: 1rem; font-size: 1.15rem; }

/* ── Forms ── */
.form {
    display: flex;
    flex-direction: column;
    gap: 0.85rem;
}

.form label {
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
    font-size: 0.875rem;
    color: var(--text-muted);
}

.form input,
.form select,
.form textarea {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    color: var(--text);
    font-size: 0.95rem;
    font-family: var(--sans-font);
    padding: 0.55rem 0.75rem;
    transition: border-color 0.15s;
    width: 100%;
}

.form input:focus,
.form select:focus,
.form textarea:focus {
    outline: none;
    border-color: var(--accent);
}

/* ── Buttons ── */
.btn {
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    border: none;
    border-radius: var(--radius-sm);
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
    padding: 0.55rem 1.1rem;
    transition: opacity 0.15s, transform 0.1s;
    text-decoration: none;
}

.btn:hover { opacity: 0.88; transform: translateY(-1px); }
.btn:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

.btn-primary  { background: var(--accent);  color: #fff; }
.btn-success  { background: var(--success); color: #000; }
.btn-danger   { background: var(--danger);  color: #000; }
.btn-secondary{ background: var(--surface2); color: var(--text); border: 1px solid var(--border); }

.btn-sm { font-size: 0.8rem; padding: 0.3rem 0.7rem; }

/* ── Tables ── */
.data-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.data-table th,
.data-table td {
    text-align: left;
    padding: 0.65rem 1rem;
    border-bottom: 1px solid var(--border);
}

.data-table th {
    background: var(--surface2);
    color: var(--text-muted);
    font-weight: 600;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.data-table tr:hover td { background: var(--surface2); }

/* ── Device cards (mobile layout) ── */
.device-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 1rem;
    margin-bottom: 0.75rem;
}

.device-card-header {
    margin-bottom: 0.75rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid var(--border);
}

.device-card-header h3 {
    margin: 0;
    font-size: 1rem;
    color: var(--text);
}

.device-card-body {
    margin-bottom: 0.75rem;
}

.device-info-row {
    display: flex;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
    align-items: flex-start;
}

.device-label {
    font-size: 0.8rem;
    color: var(--text-muted);
    font-weight: 600;
    min-width: 70px;
}

.device-value {
    font-size: 0.85rem;
    color: var(--text);
    word-break: break-all;
    flex: 1;
}

.device-badges {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

.device-card-actions {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

/* ── Flow cards (mobile layout) ── */
.flow-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 1rem;
    margin-bottom: 0.75rem;
}

.flow-card-header {
    margin-bottom: 0.75rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid var(--border);
}

.flow-card-header h3 {
    margin: 0;
    font-size: 1rem;
    color: var(--text);
}

.flow-card-body {
    margin-bottom: 0.75rem;
}

.flow-info-row {
    display: flex;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
    align-items: flex-start;
}

.flow-label {
    font-size: 0.8rem;
    color: var(--text-muted);
    font-weight: 600;
    min-width: 70px;
}

.flow-value {
    font-size: 0.85rem;
    color: var(--text);
    flex: 1;
}

.flow-badges {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

.flow-card-actions {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

/* Device cards for mobile */
.devices-card-grid { display: none; }
.flows-card-grid { display: none; }
.data-table-desktop { display: table; }

/* ── Badges ── */
.badge {
    display: inline-block;
    padding: 0.2rem 0.55rem;
    border-radius: 999px;
    font-size: 0.75rem;
    font-weight: 600;
    background: var(--surface2);
    color: var(--text-muted);
    border: 1px solid var(--border);
}

.badge-trigger { background: rgba(124,106,247,0.2); color: var(--accent-hover); border-color: var(--accent); }
.badge-action  { background: rgba(52,211,153,0.15); color: var(--success); border-color: var(--success); }

/* ── Notices ── */
.notice {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.85rem 1rem;
    font-size: 0.9rem;
    color: var(--text-muted);
    margin: 0.75rem 0;
}

.notice a { color: var(--accent-hover); }

/* ── Collapsible ── */
.collapsible {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    margin-bottom: 1.5rem;
}

.collapsible summary {
    cursor: pointer;
    padding: 1rem 1.25rem;
    font-weight: 600;
    user-select: none;
    list-style: none;
}

.collapsible summary::-webkit-details-marker { display: none; }

.collapsible .form,
.collapsible > form {
    padding: 0 1.25rem 1.25rem;
}

/* ── Scan card ── */
.scan-card {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.85rem 1rem;
    margin-bottom: 0.6rem;
    display: flex;
    align-items: center;
    gap: 0.75rem;
    flex-wrap: wrap;
}

/* ── Credential block ── */
.credential-block {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 1rem 1.25rem;
    margin-bottom: 1rem;
}

.credential-block h3 {
    margin-bottom: 0.75rem;
    font-size: 1rem;
    color: var(--text-muted);
}

/* ── Utility ── */
.mono { font-family: var(--mono-font); font-size: 0.82rem; }
.truncate { max-width: 280px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.hidden { display: none !important; }

.webhook-url {
    font-size: 0.75rem;
    color: var(--text-muted);
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 0.15rem 0.45rem;
}

/* ── Controls page ── */
.controls-error-banner {
    position: fixed;
    top: 78px;
    left: 50%;
    transform: translateX(-50%);
    width: min(920px, calc(100vw - 2rem));
    z-index: 1200;
    border-color: var(--danger);
    color: var(--danger);
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.75rem;
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.35);
}

.controls-direction-grid {
    display: grid;
    grid-template-columns: repeat(3, minmax(70px, 90px));
    gap: 0.5rem;
    align-items: center;
    justify-content: start;
}

.controls-button-row {
    display: flex;
    gap: 0.6rem;
    flex-wrap: wrap;
}

.controls-power-state-row {
    margin-top: 0.75rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.controls-apps-header {
    margin-bottom: 1rem;
}

.controls-apps-results {
    margin-top: 1rem;
}

.controls-provider-stack {
    display: grid;
    gap: 2rem;
}

.controls-provider-section {
    display: grid;
    gap: 1rem;
}

.controls-provider-header {
    margin-bottom: 0;
}

.controls-provider-header h2 {
    margin-bottom: 0.25rem;
    font-size: 1.2rem;
}

.automation-recorder-launcher {
    position: fixed;
    right: 0;
    top: 40%;
    transform: translateY(-50%);
    z-index: 38;
    border-top-right-radius: 0;
    border-bottom-right-radius: 0;
    box-shadow: 0 6px 16px color-mix(in srgb, var(--accent) 20%, transparent);
}

.automation-recorder-drawer {
    position: fixed;
    top: 88px;
    right: 0;
    width: min(420px, calc(100vw - 1.2rem));
    max-height: calc(100vh - 110px);
    z-index: 39;
    transform: translateX(102%);
    transition: transform 0.2s ease;
    pointer-events: none;
}

.automation-recorder-drawer.is-open {
    transform: translateX(0);
    pointer-events: auto;
}

.automation-recorder {
    border: 1px solid var(--border);
    border-radius: var(--radius);
    background: var(--surface);
    padding: 1rem;
    height: 100%;
    overflow: auto;
}

.automation-recorder-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.75rem;
    margin-bottom: 0.35rem;
}

.automation-recorder-header h3 {
    margin: 0;
    font-size: 1rem;
}

.automation-recorder-header-actions {
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
}

.automation-recorder-controls {
    display: grid;
    gap: 0.7rem;
}

.automation-recorder-log-anchor {
    position: relative;
}

.recording-log-popover {
    position: absolute;
    right: 0;
    top: calc(100% + 0.45rem);
    width: min(360px, 86vw);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    background: var(--surface2);
    padding: 0.55rem;
    box-shadow: 0 12px 24px rgba(0, 0, 0, 0.24);
    z-index: 2;
}

.recording-log-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
    margin-bottom: 0.35rem;
}

.recording-log-entries {
    max-height: 180px;
    overflow: auto;
    display: grid;
    gap: 0.35rem;
}

.recording-log-entry {
    font-size: 0.82rem;
    border: 1px solid color-mix(in srgb, var(--border) 80%, transparent);
    border-radius: 0.45rem;
    padding: 0.35rem 0.45rem;
}

.recording-pulse-overlay {
    position: fixed;
    right: 1rem;
    bottom: 1rem;
    z-index: 40;
    display: inline-flex;
    align-items: center;
    gap: 0.45rem;
    background: var(--surface);
    border: 1px solid var(--danger);
    border-radius: 999px;
    padding: 0.4rem 0.7rem;
    color: var(--danger);
    font-size: 0.8rem;
    font-weight: 600;
    box-shadow: 0 6px 20px color-mix(in srgb, var(--danger) 22%, transparent);
}

.recording-pulse-dot {
    width: 0.55rem;
    height: 0.55rem;
    border-radius: 999px;
    background: var(--danger);
    animation: recorder-pulse 1.2s ease-in-out infinite;
}

.recording-pulse-overlay.is-flash {
    animation: recorder-flash 0.45s ease;
}

@keyframes recorder-pulse {
    0%, 100% { opacity: 1; transform: scale(1); }
    50% { opacity: 0.45; transform: scale(0.85); }
}

@keyframes recorder-flash {
    0% { box-shadow: 0 0 0 0 color-mix(in srgb, var(--danger) 40%, transparent); }
    100% { box-shadow: 0 0 0 14px color-mix(in srgb, var(--danger) 0%, transparent); }
}

.cp-device-selector {
    display: flex;
    justify-content: space-between;
    align-items: end;
    gap: 1rem;
    flex-wrap: wrap;
}

.cp-label {
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
    font-size: 0.875rem;
    color: var(--text-muted);
    flex: 1 1 280px;
}

.cp-select,
.cp-input {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    color: var(--text);
    font-size: 0.95rem;
    font-family: var(--sans-font);
    padding: 0.55rem 0.75rem;
    width: 100%;
}

.cp-select:focus,
.cp-input:focus {
    outline: none;
    border-color: var(--accent);
}

.cp-power-row {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.cp-device-summary {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.cp-device-title {
    margin: 0;
    font-size: 1.25rem;
}

.cp-device-meta {
    color: var(--text-muted);
}

.cp-power-label {
    font-size: 0.85rem;
    color: var(--text-muted);
}

.cp-badge {
    min-width: 88px;
    text-align: center;
}

.cp-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
    gap: 1rem;
}

.cp-panel {
    margin-bottom: 0;
}

.cp-panel-wide {
    grid-column: 1 / -1;
}

.cp-panel-title {
    margin-bottom: 0.85rem;
    font-size: 1rem;
}

.cp-panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.75rem;
}

.cp-dpad {
    display: grid;
    grid-template-columns: repeat(3, minmax(60px, 76px));
    gap: 0.5rem;
    justify-content: center;
    align-items: center;
}

.cp-btn-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
    gap: 0.55rem;
}

.cp-btn {
    width: 100%;
    justify-content: center;
}

.cp-dpad-center {
    min-height: 52px;
}

.cp-input-row {
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.cp-input-row .btn {
    flex: 0 0 auto;
}

.cp-input-row .cp-input {
    flex: 1 1 260px;
}

.cp-apps-results {
    margin-top: 0.85rem;
}

.remote-page {
    display: grid;
    gap: 1rem;
}

.remote-layout {
    display: grid;
    gap: 1.25rem;
    align-items: start;
}

.remote-layout-apple {
    grid-template-columns: minmax(260px, 320px) 1fr;
}

.remote-layout-samsung {
    grid-template-columns: minmax(280px, 340px) 1fr;
}

.remote-shell {
    background: linear-gradient(180deg, #3a3a44 0%, #23232b 55%, #17171d 100%);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 40px;
    padding: 1.2rem 1rem 1.4rem;
    box-shadow: inset 0 1px 0 rgba(255,255,255,0.12), 0 22px 40px rgba(0,0,0,0.35);
    display: grid;
    gap: 0.9rem;
    justify-items: center;
}

.remote-shell-apple {
    min-height: 720px;
    max-width: 320px;
}

.remote-shell-samsung {
    min-height: 720px;
    max-width: 340px;
    border-radius: 36px;
}

.remote-shell-top {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.remote-shell-top-samsung {
    justify-content: flex-end;
}

.remote-icon-btn {
    width: 42px;
    height: 42px;
    border-radius: 999px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.08);
    color: var(--text);
    cursor: pointer;
    font-size: 1rem;
    transition: transform 0.1s, background 0.15s, border-color 0.15s;
}

.remote-icon-btn:hover {
    transform: translateY(-1px);
    background: rgba(255,255,255,0.14);
}

.remote-icon-btn-danger {
    background: rgba(248, 113, 113, 0.18);
    border-color: rgba(248, 113, 113, 0.55);
    color: #fecaca;
}

.remote-touchpad {
    position: relative;
    width: 220px;
    height: 220px;
    border-radius: 50%;
    background: radial-gradient(circle at 35% 30%, rgba(255,255,255,0.12), rgba(255,255,255,0.02) 62%, rgba(0,0,0,0.28) 100%);
    border: 1px solid rgba(255,255,255,0.12);
    box-shadow: inset 0 6px 16px rgba(255,255,255,0.05), inset 0 -10px 18px rgba(0,0,0,0.25);
}

.remote-touchpad-samsung {
    width: 210px;
    height: 210px;
}

.remote-direction,
.remote-touchpad-center {
    position: absolute;
    border: none;
    background: transparent;
    color: var(--text);
    cursor: pointer;
}

.remote-touchpad-center {
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 86px;
    height: 86px;
    border-radius: 50%;
    background: rgba(255,255,255,0.09);
    border: 1px solid rgba(255,255,255,0.12);
    font-weight: 700;
    letter-spacing: 0.03em;
}

.remote-touchpad-center-samsung {
    font-size: 0.8rem;
}

.remote-direction-up {
    top: 18px;
    left: 50%;
    transform: translateX(-50%);
}

.remote-direction-left {
    top: 50%;
    left: 18px;
    transform: translateY(-50%);
}

.remote-direction-right {
    top: 50%;
    right: 18px;
    transform: translateY(-50%);
}

.remote-direction-down {
    bottom: 18px;
    left: 50%;
    transform: translateX(-50%);
}

.remote-pill-row {
    width: 100%;
    display: grid;
    gap: 0.55rem;
}

.remote-pill-row-split {
    grid-template-columns: repeat(2, 1fr);
}

.remote-pill-btn {
    min-height: 48px;
    border-radius: 999px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.08);
    color: var(--text);
    cursor: pointer;
    font-weight: 600;
}

.remote-media-cluster {
    width: 100%;
    display: grid;
    grid-template-columns: 52px 1fr 52px;
    gap: 0.65rem;
    align-items: center;
}

.remote-play-btn,
.remote-small-btn {
    min-height: 54px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.08);
    color: var(--text);
    cursor: pointer;
}

.remote-play-btn {
    border-radius: 999px;
    font-size: 1.1rem;
}

.remote-small-btn {
    border-radius: 18px;
}

.remote-rocker-group {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 0.8rem;
}

.remote-rocker {
    background: rgba(255,255,255,0.06);
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 28px;
    display: grid;
    justify-items: center;
    overflow: hidden;
}

.remote-rocker-btn {
    width: 100%;
    min-height: 56px;
    border: none;
    background: transparent;
    color: var(--text);
    cursor: pointer;
    font-size: 1.2rem;
}

.remote-rocker-label {
    width: 100%;
    text-align: center;
    padding: 0.55rem 0.35rem;
    font-size: 0.82rem;
    color: var(--text-muted);
    border-top: 1px solid rgba(255,255,255,0.08);
    border-bottom: 1px solid rgba(255,255,255,0.08);
}

.remote-companion-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
    gap: 1rem;
}

.remote-card {
    margin-bottom: 0;
}

.remote-card-wide {
    grid-column: 1 / -1;
}

/* ── Samsung-specific remote buttons ── */

.samsung-top-row {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.5rem;
}

/* Input switching row inside the remote shell */
.samsung-input-row {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 0.4rem;
}

.samsung-input-row-secondary {
    grid-template-columns: repeat(3, 1fr);
    opacity: 0.72;
}

.samsung-input-btn {
    min-height: 38px;
    border-radius: var(--radius-sm);
    border: 1px solid rgba(255,255,255,0.14);
    background: rgba(255,255,255,0.06);
    color: var(--text);
    cursor: pointer;
    font-size: 0.78rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    transition: background 0.15s, border-color 0.15s;
}

.samsung-input-btn:hover {
    background: rgba(124,106,247,0.22);
    border-color: rgba(124,106,247,0.55);
    opacity: 1;
}

.samsung-input-btn-primary {
    background: rgba(124,106,247,0.18);
    border-color: rgba(124,106,247,0.4);
    opacity: 1;
}

/* Companion card inputs grid */
.samsung-inputs-companion-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(110px, 1fr));
    gap: 0.5rem;
    margin: 0.5rem 0 0.75rem;
}

.samsung-input-companion-btn {
    min-height: 46px;
    border-radius: var(--radius-sm);
    border: 1px solid var(--border);
    background: var(--surface2);
    color: var(--text);
    cursor: pointer;
    font-size: 0.85rem;
    font-weight: 600;
    transition: background 0.15s, border-color 0.15s, transform 0.1s;
}

.samsung-input-companion-btn:hover {
    background: rgba(124,106,247,0.18);
    border-color: var(--accent);
    transform: translateY(-1px);
}

.samsung-input-companion-primary {
    background: rgba(124,106,247,0.14);
    border-color: rgba(124,106,247,0.45);
}

.samsung-input-tier-label {
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--text-muted);
    margin-top: 0.6rem;
    margin-bottom: 0.25rem;
}

.samsung-input-tier-warning {
    color: #fbbf24;
}

.samsung-source-btn {
    flex: 1;
    min-height: 42px;
    border-radius: 999px;
    border: 1px solid rgba(255,255,255,0.14);
    background: rgba(255,255,255,0.08);
    color: var(--text);
    cursor: pointer;
    font-size: 0.85rem;
    font-weight: 600;
    transition: background 0.15s;
}

.samsung-source-btn:hover { background: rgba(255,255,255,0.15); }

.samsung-sys-row {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 0.45rem;
}

.samsung-sys-btn {
    min-height: 42px;
    border-radius: var(--radius-sm);
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.07);
    color: var(--text);
    cursor: pointer;
    font-size: 1rem;
    transition: background 0.15s;
}

.samsung-sys-btn:hover { background: rgba(255,255,255,0.14); }

.samsung-nav-row {
    width: 100%;
    display: grid;
    grid-template-columns: 1fr 44px 1fr;
    gap: 0.45rem;
    align-items: center;
}

.samsung-nav-btn {
    min-height: 42px;
    border-radius: 999px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.07);
    color: var(--text);
    cursor: pointer;
    font-size: 0.82rem;
    font-weight: 600;
    transition: background 0.15s;
}

.samsung-nav-btn:hover { background: rgba(255,255,255,0.14); }

.samsung-nav-btn-home {
    border-radius: 50%;
    font-size: 1.1rem;
    padding: 0;
}

.samsung-rocker-group {
    grid-template-columns: repeat(3, 1fr);
}

.samsung-media-row {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 0.35rem;
    align-items: center;
}

.samsung-media-btn {
    min-height: 44px;
    border-radius: 10px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.07);
    color: var(--text);
    cursor: pointer;
    font-size: 0.95rem;
    transition: background 0.15s;
}

.samsung-media-btn:hover { background: rgba(255,255,255,0.15); }

.samsung-media-btn-play {
    background: rgba(124,106,247,0.22);
    border-color: rgba(124,106,247,0.55);
}

.samsung-colour-row {
    width: 100%;
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 0.45rem;
}

.samsung-colour-btn {
    min-height: 44px;
    border-radius: 999px;
    border: none;
    color: #fff;
    font-weight: 700;
    cursor: pointer;
    font-size: 0.9rem;
    transition: opacity 0.15s, transform 0.1s;
}

.samsung-colour-btn:hover { opacity: 0.85; transform: translateY(-1px); }
.samsung-colour-red    { background: #e53935; }
.samsung-colour-green  { background: #43a047; }
.samsung-colour-yellow { background: #f9a825; }
.samsung-colour-blue   { background: #1e88e5; }

.samsung-numpad {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 0.5rem;
}

.samsung-num-btn {
    min-height: 52px;
    border-radius: var(--radius-sm);
    border: 1px solid rgba(255,255,255,0.12);
    background: var(--surface2);
    color: var(--text);
    font-size: 1.1rem;
    font-weight: 700;
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
}

.samsung-num-btn:hover {
    background: rgba(124,106,247,0.18);
    border-color: var(--accent);
    transform: translateY(-1px);
}

/* ── Automation builder ── */
.automation-builder {
    display: grid;
    grid-template-columns: minmax(220px, 280px) 1fr;
    gap: 1rem;
    align-items: start;
}

.automation-palette,
.automation-sequence {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.9rem;
}

.automation-palette h3,
.automation-sequence h3 {
    margin-bottom: 0.25rem;
    font-size: 1rem;
}

.palette-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
    border: 1px dashed var(--border);
    border-radius: var(--radius-sm);
    padding: 0.55rem 0.6rem;
    margin-bottom: 0.5rem;
    background: var(--surface);
    cursor: grab;
}

.palette-item:active {
    cursor: grabbing;
}

.sequence-step {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.7rem;
    margin-bottom: 0.6rem;
}

.sequence-step-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.5rem;
}

/* ── Responsive ── */

/* Tablet (640px - 1023px) */
@media (max-width: 1023px) {
    html { font-size: 15px; }
    .container { padding: 0 1.5rem; margin: 1.5rem auto; }
    .card-grid { grid-template-columns: repeat(auto-fill, minmax(160px, 1fr)); }
    .automation-builder { grid-template-columns: 1fr; gap: 1.5rem; }
    .automation-palette { margin-bottom: 0.5rem; }
}

/* Mobile (max 640px) */
@media (max-width: 640px) {
    html { font-size: 14px; }

    /* Header adjustments */
    .site-header { padding: 0 1rem; }
    .header-inner {
        flex-direction: column;
        height: auto;
        padding: 0.75rem 0;
        gap: 0.5rem;
    }
    .logo { font-size: 1.1rem; }

    /* Navigation */
    nav {
        gap: 0.6rem;
        flex-wrap: wrap;
        justify-content: center;
    }
    nav a { font-size: 0.8rem; }
    .header-subnav-inner {
        gap: 0.65rem;
        padding: 0.35rem 0 0.45rem;
    }
    .header-subnav-link {
        font-size: 0.74rem;
    }

    /* Container & spacing */
    .container { padding: 0 1rem; margin: 1rem auto; }
    .page-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 0.75rem;
    }
    .page-header h1 { font-size: 1.5rem; }

    /* Hero */
    .hero h1 { font-size: 1.8rem; }
    .subtitle { font-size: 0.95rem; }

    /* Card grid */
    .card-grid { grid-template-columns: 1fr; }
    .card { padding: 1.25rem; }
    .card-icon { font-size: 1.75rem; }
    .card h2 { font-size: 1rem; }

    /* Forms & inputs (touch-friendly) */
    .form label { font-size: 0.8rem; }
    .form input,
    .form select,
    .form textarea {
        font-size: 1rem; /* Prevent zoom on iOS */
        padding: 0.7rem;
        min-height: 44px; /* Touch target minimum */
    }

    /* Tables – horizontal scroll on mobile */
    .data-table {
        font-size: 0.8rem;
        display: none;
    }
    .data-table-desktop {
        display: none !important;
    }
    .devices-card-grid {
        display: block;
    }
    .flows-card-grid {
        display: block;
    }

    /* Buttons – touch-friendly sizing */
    .btn {
        font-size: 0.85rem;
        padding: 0.65rem 1rem;
        min-height: 44px;
        min-width: 44px;
    }
    .btn-sm { padding: 0.4rem 0.6rem; min-height: 36px; }

    /* Controls */
    .controls-direction-grid {
        grid-template-columns: repeat(3, 1fr);
        gap: 0.4rem;
    }
    .controls-button-row {
        gap: 0.4rem;
        flex-direction: column;
        align-items: stretch;
    }
    .controls-button-row .btn { width: 100%; }
    .controls-power-state-row {
        flex-direction: column;
        align-items: stretch;
        gap: 0.4rem;
    }
    .controls-error-banner {
        width: calc(100vw - 1rem);
        flex-direction: column;
        gap: 0.5rem;
        padding: 0.75rem;
    }
    .controls-provider-header {
        align-items: flex-start;
    }
    .remote-layout-apple,
    .remote-layout-samsung {
        grid-template-columns: 1fr;
    }
    .remote-shell {
        max-width: 100%;
        min-height: auto;
    }
    .remote-touchpad,
    .remote-touchpad-samsung {
        width: 200px;
        height: 200px;
    }
    .cp-device-selector,
    .cp-power-row,
    .cp-panel-header,
    .cp-input-row {
        flex-direction: column;
        align-items: stretch;
    }
    .cp-grid,
    .cp-btn-grid {
        grid-template-columns: 1fr;
    }
    .cp-dpad {
        grid-template-columns: repeat(3, 1fr);
    }
    .remote-companion-grid {
        grid-template-columns: 1fr;
    }
    .remote-rocker-group,
    .samsung-rocker-group,
    .remote-pill-row-split,
    .remote-media-cluster,
    .samsung-media-row,
    .samsung-sys-row {
        grid-template-columns: 1fr;
    }
    .samsung-colour-row {
        grid-template-columns: repeat(4, 1fr);
    }
    .samsung-numpad {
        grid-template-columns: repeat(3, 1fr);
    }
    .samsung-nav-row {
        grid-template-columns: 1fr 44px 1fr;
    }
    .cp-input-row .btn,
    .cp-input-row .cp-input {
        width: 100%;
        flex: 1 1 auto;
    }
    .automation-recorder-launcher {
        top: auto;
        bottom: 0.9rem;
        right: 0.8rem;
        transform: none;
        border-radius: 999px;
    }
    .automation-recorder-drawer {
        top: auto;
        bottom: 4.2rem;
        right: 0.5rem;
        width: calc(100vw - 1rem);
        max-height: 70vh;
    }
    .recording-log-popover {
        right: auto;
        left: 0;
        width: min(340px, 82vw);
    }

    /* Automation builder */
    .automation-builder {
        grid-template-columns: 1fr;
        gap: 1rem;
    }
    .automation-palette,
    .automation-sequence {
        padding: 0.75rem;
    }
    .palette-item {
        flex-direction: column;
        gap: 0.4rem;
    }
    .palette-item span,
    .palette-item button {
        width: 100%;
        text-align: center;
    }
    .sequence-step {
        padding: 0.6rem;
    }
    .sequence-step-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 0.4rem;
    }
    .sequence-step-header strong { word-break: break-word; }

    /* Collapsible */
    .collapsible summary {
        padding: 0.85rem 1rem;
        font-size: 0.95rem;
    }
    .collapsible .form,
    .collapsible > form {
        padding: 0 1rem 1rem;
    }

    /* Badges */
    .badge { font-size: 0.7rem; padding: 0.15rem 0.4rem; }

    /* Utilities */
    .truncate { max-width: 100%; }
    .mono { font-size: 0.75rem; }
    .webhook-url {
        font-size: 0.7rem;
        max-width: 100%;
        overflow-x: auto;
        -webkit-overflow-scrolling: touch;
        display: inline-block;
        word-break: break-all;
        max-height: 2.5rem;
        padding: 0.25rem 0.4rem;
        overflow-y: hidden;
    }

    /* Footer */
    .site-footer { padding: 1rem; font-size: 0.75rem; }
}

/* Ultra-mobile (max 380px) */
@media (max-width: 380px) {
    html { font-size: 13px; }
    .page-header h1 { font-size: 1.3rem; }
    .hero h1 { font-size: 1.5rem; }
    .btn, .btn-sm { padding: 0.6rem 0.8rem; }
    .controls-direction-grid { grid-template-columns: repeat(2, 1fr); }
}

/* ── Delay Slider ──────────────────────────────────────────────────────────── */
.delay-slider-row {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
    padding: 0.75rem 0;
    border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
    margin-bottom: 0.5rem;
}

.delay-slider-label {
    font-size: 0.85rem;
    font-weight: 500;
    color: var(--text-muted);
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.5rem;
}

.delay-slider-display {
    font-variant-numeric: tabular-nums;
    font-weight: 700;
    color: var(--accent);
    min-width: 3.5rem;
    text-align: right;
}

.delay-slider {
    width: 100%;
    accent-color: var(--accent);
    cursor: pointer;
    height: 4px;
}

.delay-slider-ticks {
    display: flex;
    justify-content: space-between;
    font-size: 0.7rem;
    color: var(--text-muted);
    padding: 0 2px;
}

/* ── Clickable flow table rows ─────────────────────────────────────────────── */
.flow-table-row {
    cursor: pointer;
    transition: background 0.12s;
}

.flow-table-row:hover {
    background: color-mix(in srgb, var(--accent) 8%, var(--surface));
}

.flow-table-row.is-previewing {
    background: color-mix(in srgb, var(--accent) 14%, var(--surface));
    outline: 2px solid var(--accent);
    outline-offset: -2px;
}

.flow-card {
    cursor: pointer;
    transition: box-shadow 0.12s, outline 0.12s;
}

.flow-card.is-previewing {
    outline: 2px solid var(--accent);
    box-shadow: 0 0 0 4px color-mix(in srgb, var(--accent) 20%, transparent);
}

/* ── Flow Visualizer Panel ─────────────────────────────────────────────────── */
.flow-visualizer {
    border: 1px solid var(--border);
    border-radius: var(--radius);
    background: var(--surface);
    padding: 1.25rem 1.5rem;
    margin: 1.25rem 0;
    animation: viz-slide-in 0.18s ease;
}

.flow-visualizer.hidden {
    display: none;
}

@keyframes viz-slide-in {
    from { opacity: 0; transform: translateY(-6px); }
    to   { opacity: 1; transform: translateY(0); }
}

.flow-visualizer-header {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.flow-visualizer-header h3 {
    margin: 0;
    font-size: 1rem;
    flex: 1 1 auto;
}

.flow-visualizer-meta {
    font-size: 0.78rem;
    color: var(--text-muted);
    flex: 0 0 auto;
}

.flow-visualizer-steps {
    display: flex;
    flex-wrap: nowrap;
    align-items: center;
    gap: 0.5rem;
    overflow-x: auto;
    padding-bottom: 0.35rem;
}

/* ── Visualizer step nodes ─────────────────────────────────────────────────── */
.viz-step {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    background: color-mix(in srgb, var(--text-muted) 8%, var(--surface));
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.55rem 0.85rem;
    min-width: 220px;
    flex: 0 0 auto;
    transition: border-color 0.2s ease, background 0.2s ease, box-shadow 0.2s ease;
}

.viz-step.is-running {
    border-color: var(--accent);
    box-shadow: 0 0 0 2px color-mix(in srgb, var(--accent) 24%, transparent);
}

.viz-step.is-complete {
    background: color-mix(in srgb, var(--success) 16%, var(--surface));
    border-color: color-mix(in srgb, var(--success) 65%, var(--border));
}

.viz-step.is-error {
    background: color-mix(in srgb, var(--danger) 14%, var(--surface));
    border-color: color-mix(in srgb, var(--danger) 65%, var(--border));
}

.viz-step-icon {
    font-size: 1.1rem;
    width: 1.6rem;
    text-align: center;
    flex-shrink: 0;
}

.viz-step-body {
    display: flex;
    flex-direction: column;
    gap: 0.1rem;
}

.viz-step-num {
    font-size: 0.68rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.04em;
}

.viz-step-label {
    font-size: 0.88rem;
    font-weight: 500;
}

/* Arrow and optional delay between steps */
.viz-link {
    display: flex;
    align-items: center;
    gap: 0.35rem;
    flex: 0 0 auto;
}

.viz-arrow {
    color: var(--text-muted);
    font-size: 1.1rem;
    line-height: 1;
    transition: color 0.2s ease;
}

.viz-link.is-active .viz-arrow,
.viz-link.is-complete .viz-arrow {
    color: var(--success);
}

.viz-link.is-error .viz-arrow {
    color: var(--danger);
}

/* Delay badge between steps */
.viz-delay {
    font-size: 0.72rem;
    color: var(--accent);
    background: color-mix(in srgb, var(--accent) 10%, var(--surface));
    border: 1px solid color-mix(in srgb, var(--accent) 30%, transparent);
    border-radius: 999px;
    padding: 0.15rem 0.6rem;
    margin: 0;
    font-variant-numeric: tabular-nums;
    transition: border-color 0.2s ease, color 0.2s ease;
}

.viz-link.is-active .viz-delay,
.viz-link.is-complete .viz-delay {
    color: var(--success);
    border-color: color-mix(in srgb, var(--success) 50%, transparent);
}

@media (max-width: 640px) {
    .delay-slider-label { flex-direction: column; align-items: flex-start; }
    .delay-slider-display { text-align: left; }
    .flow-visualizer { padding: 0.9rem 1rem; }
    .viz-step { min-width: 180px; }
}

{% extends "base.html" %}
{% block title %}Controls · Home Automation Server{% endblock %}

{% block header_subnav %}
{% if controls_devices %}
<div class="header-subnav">
    <div class="header-subnav-inner">
        {% for device in controls_devices %}
        <a
            href="{{ device.route }}"
            class="header-subnav-link{% if device.is_selected %} is-active{% endif %}"
            {% if device.is_selected %}aria-current="page"{% endif %}
        >
            {% if device.kind == 'apple_tv' %}
            {{ device.name }} (Apple TV)
            {% else %}
            {{ device.name }}
            {% endif %}
        </a>
        {% endfor %}
    </div>
</div>
{% endif %}
{% endblock %}

{% block content %}
<div class="page-header">
    <h1>Device Controls</h1>
</div>

<div id="controls-error-banner" class="notice hidden controls-error-banner">
    <span id="controls-error-banner-text"></span>
    <button type="button" class="btn btn-sm btn-secondary" onclick="clearErrorBanner()" aria-label="Dismiss error">✕</button>
</div>

<div
    id="controls-page-data"
    data-selected-device-id="{{ selected_device.id if selected_device else '' }}"
    data-selected-device-kind="{{ selected_device_kind or '' }}"
></div>

{% if not controls_devices %}
<div class="notice">No devices saved. <a href="/ui/devices">Add a device first.</a></div>
{% else %}
{% if selected_device %}
<section class="controls-provider-section">
    <div class="page-header controls-provider-header">
        <div>
            <h2>
                {% if selected_device_kind == 'apple_tv' %}
                Apple TV Remote
                {% else %}
                Samsung TV Remote
                {% endif %}
            </h2>
            <p class="subtitle">
                {% if selected_device_kind == 'apple_tv' %}
                Directional, playback, power, and installed-app controls for {{ selected_device.name }}.
                {% else %}
                Samsung key commands, power actions, and manual app launch for {{ selected_device.name }}.
                {% endif %}
            </p>
        </div>
    </div>

    <div class="automation-recorder" id="automation-recorder">
        <div class="automation-recorder-header">
            <h3>Record automation</h3>
            <span id="recording-indicator" class="badge">Idle</span>
        </div>
        <p class="subtitle">Capture your button presses, keep realistic waits, then save as a sequence flow.</p>
        <div class="automation-recorder-controls">
            <label>Flow name
                <input type="text" id="recording-flow-name" placeholder="Recorded flow" />
            </label>
            <label>Wait sensitivity
                <input type="range" id="recording-wait-threshold" min="100" max="1500" step="50" value="300" oninput="updateRecorderSensitivityLabel()" />
                <span id="recording-wait-threshold-value" class="mono">300 ms min gap</span>
            </label>
            <div class="controls-button-row">
                <button type="button" class="btn btn-danger" id="recording-start-btn" onclick="startRecording()">Start Recording</button>
                <button type="button" class="btn btn-secondary" id="recording-stop-btn" onclick="stopRecording()" disabled>Stop</button>
                <button type="button" class="btn btn-secondary" id="recording-clear-btn" onclick="clearRecording()" disabled>Clear</button>
                <button type="button" class="btn btn-success" id="recording-save-btn" onclick="saveRecordingAsFlow()" disabled>Save as Flow</button>
            </div>
        </div>
        <div id="recording-status" class="notice hidden"></div>
        <div id="recording-preview" class="notice hidden"></div>
    </div>

    <div id="recording-pulse-overlay" class="recording-pulse-overlay hidden" aria-live="polite">
        <span class="recording-pulse-dot" aria-hidden="true"></span>
        <span id="recording-pulse-text">REC</span>
    </div>

    {% if selected_device_kind == 'apple_tv' %}
    {% include "partials/controls_appletv.html" %}
    {% elif selected_device_kind == 'samsung_tv' %}
    {% include "partials/controls_samsung.html" %}
    {% endif %}
</section>
{% endif %}
{% endif %}
{% endblock %}

{% block scripts %}
<script>
const controlsPageData = document.getElementById('controls-page-data');
const selectedDeviceId = controlsPageData && controlsPageData.dataset.selectedDeviceId
    ? parseInt(controlsPageData.dataset.selectedDeviceId, 10)
    : null;
const selectedDeviceKind = controlsPageData && controlsPageData.dataset.selectedDeviceKind
    ? controlsPageData.dataset.selectedDeviceKind
    : null;

let errorBannerTimer = null;
let isRecording = false;
let recordingActions = [];
let lastRecordedAtMs = 0;
let recordingPulseTimer = null;

function clearErrorBanner() {
    const banner = document.getElementById('controls-error-banner');
    const text = document.getElementById('controls-error-banner-text');
    if (!banner) return;
    if (errorBannerTimer) {
        clearTimeout(errorBannerTimer);
        errorBannerTimer = null;
    }
    banner.classList.add('hidden');
    if (text) {
        text.textContent = '';
    }
}

function showErrorBanner(message) {
    const banner = document.getElementById('controls-error-banner');
    const text = document.getElementById('controls-error-banner-text');
    if (!banner) return;
    if (errorBannerTimer) {
        clearTimeout(errorBannerTimer);
        errorBannerTimer = null;
    }
    banner.classList.remove('hidden');
    if (text) {
        text.textContent = '❌ ' + (message || 'Unexpected error');
    }
    errorBannerTimer = setTimeout(() => {
        clearErrorBanner();
    }, 6000);
}

document.addEventListener('DOMContentLoaded', () => {
    clearErrorBanner();
    clearNotice('control-status');
    clearNotice('atv-apps-status');
    clearNotice('samsung-status');
    clearNotice('samsung-app-status');
    if (selectedDeviceKind === 'apple_tv') {
        atvClearAppsResults();
        atvRefreshPower();
    }
    updateRecorderSensitivityLabel();
    refreshRecorderUi();
});

function getRecordingWaitThresholdMs() {
    const raw = document.getElementById('recording-wait-threshold')?.value || '300';
    return Math.max(0, parseInt(raw, 10) || 300);
}

function updateRecorderSensitivityLabel() {
    const label = document.getElementById('recording-wait-threshold-value');
    if (label) label.textContent = `${getRecordingWaitThresholdMs()} ms min gap`;
}

function setRecordingStatus(message, ok = true) {
    const box = document.getElementById('recording-status');
    if (!box) return;
    if (!message) {
        box.classList.add('hidden');
        box.textContent = '';
        return;
    }
    box.classList.remove('hidden');
    box.textContent = (ok ? 'OK: ' : 'Error: ') + message;
}

function setRecordingIndicator() {
    const indicator = document.getElementById('recording-indicator');
    if (!indicator) return;
    indicator.textContent = isRecording ? 'Recording' : 'Idle';
    indicator.style.borderColor = isRecording ? 'var(--danger)' : '';
    indicator.style.color = isRecording ? 'var(--danger)' : '';
}

function setRecordingPulseVisible(visible) {
    const overlay = document.getElementById('recording-pulse-overlay');
    if (!overlay) return;
    overlay.classList.toggle('hidden', !visible);
    if (!visible) overlay.classList.remove('is-flash');
}

function actionLabel(type, payload) {
    if (type === 'remote_command') return String(payload?.command || 'command');
    if (type === 'power') return payload?.turn_on ? 'power on' : 'power off';
    if (type === 'launch_app') return `launch ${payload?.bundle_id || payload?.app_id || 'app'}`;
    if (type === 'wait_seconds') return `wait ${payload?.seconds || '?'}s`;
    return type;
}

function flashRecordingPulse(type, payload) {
    if (!isRecording) return;
    const overlay = document.getElementById('recording-pulse-overlay');
    const text = document.getElementById('recording-pulse-text');
    if (!overlay || !text) return;

    text.textContent = `REC ${recordingActions.length}: ${actionLabel(type, payload)}`;
    overlay.classList.remove('hidden');
    overlay.classList.remove('is-flash');
    void overlay.offsetWidth;
    overlay.classList.add('is-flash');

    if (recordingPulseTimer) clearTimeout(recordingPulseTimer);
    recordingPulseTimer = setTimeout(() => {
        if (!isRecording) setRecordingPulseVisible(false);
    }, 700);
}

function refreshRecorderPreview() {
    const preview = document.getElementById('recording-preview');
    if (!preview) return;
    if (recordingActions.length === 0) {
        preview.classList.add('hidden');
        preview.textContent = '';
        return;
    }
    const lines = recordingActions.map((action, index) => {
        if (action.type === 'wait_seconds') return `${index + 1}. Wait ${action.payload.seconds}s`;
        if (action.type === 'remote_command') return `${index + 1}. ${action.payload.command}`;
        if (action.type === 'power') return `${index + 1}. Power ${action.payload.turn_on ? 'On' : 'Off'}`;
        if (action.type === 'launch_app') return `${index + 1}. Launch ${action.payload.bundle_id || action.payload.app_id || '?'}`;
        return `${index + 1}. ${action.type}`;
    });
    preview.classList.remove('hidden');
    preview.textContent = lines.join('  |  ');
}

function refreshRecorderUi() {
    const startBtn = document.getElementById('recording-start-btn');
    const stopBtn = document.getElementById('recording-stop-btn');
    const clearBtn = document.getElementById('recording-clear-btn');
    const saveBtn = document.getElementById('recording-save-btn');
    if (startBtn) startBtn.disabled = isRecording;
    if (stopBtn) stopBtn.disabled = !isRecording;
    if (clearBtn) clearBtn.disabled = isRecording || recordingActions.length === 0;
    if (saveBtn) saveBtn.disabled = isRecording || recordingActions.length === 0;
    setRecordingIndicator();
    setRecordingPulseVisible(isRecording);
    if (isRecording) {
        const pulseText = document.getElementById('recording-pulse-text');
        if (pulseText) pulseText.textContent = `REC ${recordingActions.length}`;
    }
    refreshRecorderPreview();
}

function startRecording() {
    clearErrorBanner();
    recordingActions = [];
    lastRecordedAtMs = 0;
    isRecording = true;
    setRecordingStatus('Recording started. Use remote controls to capture a flow.');
    refreshRecorderUi();
}

function stopRecording() {
    isRecording = false;
    setRecordingStatus(`Recording stopped. Captured ${recordingActions.length} step(s).`);
    refreshRecorderUi();
}

function clearRecording() {
    recordingActions = [];
    lastRecordedAtMs = 0;
    setRecordingStatus('Recording cleared.');
    refreshRecorderUi();
}

function maybeRecordWait(nowMs) {
    if (!lastRecordedAtMs) return;
    const gapMs = nowMs - lastRecordedAtMs;
    const thresholdMs = getRecordingWaitThresholdMs();
    if (gapMs < thresholdMs) return;
    const seconds = Math.max(0.1, Math.round((gapMs / 1000) * 10) / 10);
    recordingActions.push({ type: 'wait_seconds', payload: { seconds } });
}

function recordAction(type, payload) {
    if (!isRecording) return;
    const nowMs = Date.now();
    maybeRecordWait(nowMs);
    recordingActions.push({ type, payload: payload || {} });
    flashRecordingPulse(type, payload);
    lastRecordedAtMs = nowMs;
    setRecordingStatus(`Recorded ${recordingActions.length} step(s).`);
    refreshRecorderUi();
}

async function saveRecordingAsFlow() {
    if (recordingActions.length === 0) {
        setRecordingStatus('Nothing recorded yet.', false);
        return;
    }
    if (!Number.isInteger(selectedDeviceId) || !selectedDeviceKind) {
        setRecordingStatus('No selected device found for saving this flow.', false);
        return;
    }

    const flowNameInput = document.getElementById('recording-flow-name');
    const flowName = (flowNameInput?.value || '').trim() || `Recorded ${selectedDeviceKind} flow ${new Date().toLocaleString()}`;
    const payload = {
        name: flowName,
        device_kind: selectedDeviceKind,
        device_id: selectedDeviceId,
        trigger_type: 'manual',
        trigger_payload: '{}',
        action_type: 'sequence',
        action_payload: JSON.stringify({ actions: recordingActions }),
    };

    try {
        clearErrorBanner();
        const res = await fetch('/automations/', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
        });
        const data = await res.json().catch(() => ({}));
        if (!res.ok) {
            const msg = data.detail || 'Failed to save recorded automation';
            setRecordingStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        setRecordingStatus(`Saved flow "${flowName}" with ${recordingActions.length} step(s).`);
        isRecording = false;
        refreshRecorderUi();
    } catch (err) {
        const msg = String(err);
        setRecordingStatus(msg, false);
        showErrorBanner(msg);
    }
}

function requireSelectedDeviceId(label) {
    if (!Number.isInteger(selectedDeviceId)) {
        throw new Error(`Select a ${label} device first`);
    }
    return selectedDeviceId;
}

function setNotice(elementId, message, ok = true) {
    const box = document.getElementById(elementId);
    if (!box) return;
    box.classList.remove('hidden');
    box.textContent = (ok ? '✅ ' : '❌ ') + message;
}

function clearNotice(elementId) {
    const box = document.getElementById(elementId);
    if (!box) return;
    box.classList.add('hidden');
    box.textContent = '';
}

function clearAppsResults(resultsId, statusId) {
    const results = document.getElementById(resultsId);
    const status = document.getElementById(statusId);
    if (results) {
        results.classList.add('hidden');
        results.innerHTML = '';
    }
    if (status) {
        status.classList.add('hidden');
        status.textContent = '';
    }
}

function setPowerStateBadge(badgeId, state, ok = true) {
    const badge = document.getElementById(badgeId);
    if (!badge) return;

    const normalized = String(state || 'unknown').toLowerCase();
    badge.textContent = normalized.charAt(0).toUpperCase() + normalized.slice(1);

    // Reset inline styles so state transitions don't stack
    badge.style.borderColor = '';
    badge.style.color = '';

    if (!ok) {
        badge.textContent = 'Unavailable';
        badge.style.borderColor = '#f87171';
        badge.style.color = '#f87171';
        return;
    }

    if (normalized === 'on') {
        badge.style.borderColor = '#34d399';
        badge.style.color = '#34d399';
    } else if (normalized === 'off') {
        badge.style.borderColor = '#f87171';
        badge.style.color = '#f87171';
    } else {
        badge.style.borderColor = '#fbbf24';
        badge.style.color = '#fbbf24';
    }
}

function atvSelectedDeviceId() {
    return requireSelectedDeviceId('Apple TV');
}

function atvSetStatus(message, ok = true) {
    setNotice('control-status', message, ok);
}

function atvSetAppsStatus(message, ok = true) {
    setNotice('atv-apps-status', message, ok);
}

function atvClearAppsResults() {
    clearAppsResults('atv-apps-results', 'atv-apps-status');
}

async function atvRefreshPower() {
    try {
        clearErrorBanner();
        const res = await fetch(`/controls/power-state/${atvSelectedDeviceId()}`);
        const data = await res.json();
        if (!res.ok) {
            setPowerStateBadge('atv-power-badge', 'unknown', false);
            if (res.status !== 501) {
                const msg = data.detail || 'Failed to get power state';
                atvSetStatus(msg, false);
                showErrorBanner(msg);
            } else {
                const msg = data.detail || 'Power state not supported on this device';
                atvSetStatus(msg, false);
            }
            return;
        }
        setPowerStateBadge('atv-power-badge', data.power_state, true);
    } catch (err) {
        setPowerStateBadge('atv-power-badge', 'unknown', false);
        const msg = String(err);
        atvSetStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function atvCmd(command) {
    try {
        clearErrorBanner();
        const res = await fetch('/controls/appletv/command', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: atvSelectedDeviceId(), command })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to send command';
            atvSetStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        atvSetStatus(`Sent command: ${command}`);
        recordAction('remote_command', { command });
    } catch (err) {
        const msg = String(err);
        atvSetStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function atvPower(turnOn) {
    try {
        clearErrorBanner();
        const res = await fetch('/controls/appletv/power', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: atvSelectedDeviceId(), turn_on: turnOn })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to change power state';
            atvSetStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        atvSetStatus(`Power ${turnOn ? 'on' : 'off'} command sent`);
        recordAction('power', { turn_on: turnOn });
        setTimeout(atvRefreshPower, 1200);
    } catch (err) {
        const msg = String(err);
        atvSetStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function atvFetchApps() {
    const results = document.getElementById('atv-apps-results');
    if (!results) return;
    results.classList.remove('hidden');
    results.innerHTML = '⏳ Loading installed apps…';

    try {
        clearErrorBanner();
        const res = await fetch(`/apps/list/${atvSelectedDeviceId()}`);
        const data = await res.json();
        if (!res.ok) {
            results.innerHTML = '';
            if (res.status === 501) {
                results.classList.remove('hidden');
                results.innerHTML = `
                    <div class="notice">
                        This device does not support installed app listing via pyatv.<br/>
                        You can still launch an app manually using a bundle ID above.
                    </div>
                `;
            }
            const msg = data.detail || 'Failed to list apps';
            atvSetAppsStatus(msg, false);
            if (res.status !== 501) {
                showErrorBanner(msg);
            }
            return;
        }

        if (data.length === 0) {
            results.innerHTML = '<div class="notice">No apps returned by the device.</div>';
            atvSetAppsStatus('App list loaded');
            return;
        }

        results.innerHTML = `
            <table class="data-table">
                <thead>
                    <tr>
                        <th>App Name</th>
                        <th>Bundle ID</th>
                        <th>Action</th>
                    </tr>
                </thead>
                <tbody>
                    ${data.map(app => `
                        <tr>
                            <td>${escapeHtml(app.name || 'Unknown')}</td>
                            <td class="mono">${escapeHtml(app.bundle_id || '')}</td>
                            <td>
                                <button class="btn btn-sm btn-success" onclick="atvLaunchApp('${escapeJs(app.bundle_id || '')}')">Launch</button>
                            </td>
                        </tr>
                    `).join('')}
                </tbody>
            </table>
        `;
        atvSetAppsStatus(`Loaded ${data.length} app(s)`);
    } catch (err) {
        results.innerHTML = '';
        const msg = String(err);
        atvSetAppsStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function atvLaunchApp(bundleId) {
    try {
        clearErrorBanner();
        const res = await fetch('/apps/appletv/launch', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: atvSelectedDeviceId(), bundle_id: bundleId })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to launch app';
            atvSetAppsStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        atvSetAppsStatus(`Launched ${bundleId}`);
        recordAction('launch_app', { bundle_id: bundleId });
    } catch (err) {
        const msg = String(err);
        atvSetAppsStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function atvLaunchBundle(event) {
    event.preventDefault();
    const bundleId = document.getElementById('atv-bundle-id').value.trim();
    if (!bundleId) {
        const msg = 'Enter a bundle ID first';
        atvSetAppsStatus(msg, false);
        showErrorBanner(msg);
        return;
    }
    await atvLaunchApp(bundleId);
}

function samsungSelectedDeviceId() {
    return requireSelectedDeviceId('Samsung TV');
}

function samsungSetStatus(message, ok = true) {
    setNotice('samsung-status', message, ok);
}

function samsungSetAppStatus(message, ok = true) {
    setNotice('samsung-app-status', message, ok);
}


async function samsungCmd(command) {
    try {
        clearErrorBanner();
        const res = await fetch('/controls/samsung/command', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: samsungSelectedDeviceId(), command })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to send Samsung command';
            samsungSetStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        samsungSetStatus(`Sent command: ${command}`);
        recordAction('remote_command', { command });
    } catch (err) {
        const msg = String(err);
        samsungSetStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function samsungPower(turnOn) {
    try {
        clearErrorBanner();
        const res = await fetch('/controls/samsung/power', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: samsungSelectedDeviceId(), turn_on: turnOn })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to change Samsung power state';
            samsungSetStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        samsungSetStatus(`Power ${turnOn ? 'on' : 'off'} command sent`);
        recordAction('power', { turn_on: turnOn });
    } catch (err) {
        const msg = String(err);
        samsungSetStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function samsungLaunchApp(event) {
    event.preventDefault();
    const appId = document.getElementById('samsung-app-id').value.trim();
    if (!appId) {
        const msg = 'Enter a Samsung app ID first';
        samsungSetAppStatus(msg, false);
        showErrorBanner(msg);
        return;
    }

    try {
        clearErrorBanner();
        const res = await fetch('/apps/samsung/launch', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: samsungSelectedDeviceId(), app_id: appId })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to launch Samsung app';
            samsungSetAppStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        samsungSetAppStatus(`Launched ${appId}`);
        recordAction('launch_app', { app_id: appId });
    } catch (err) {
        const msg = String(err);
        samsungSetAppStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function samsungFetchSources() {
    try {
        clearErrorBanner();
        const res = await fetch(`/controls/samsung/sources/${samsungSelectedDeviceId()}`);
        const data = await res.json();
        if (!res.ok) {
            showErrorBanner(data.detail || 'Failed to fetch sources');
            return;
        }
        // Re-render the companion grid with the authoritative input list from the server
        const grid = document.getElementById('samsung-inputs-grid');
        if (!grid || !data.inputs) return;
        grid.innerHTML = data.inputs.map(input => `
            <button class="samsung-input-companion-btn" onclick="samsungCmd('${escapeJs(input.command)}')">
                ${escapeHtml(input.icon)} ${escapeHtml(input.label)}
            </button>
        `).join('') + `
            <button class="samsung-input-companion-btn" onclick="samsungCmd('source')">⬡ Source Menu</button>
        `;
    } catch (err) {
        showErrorBanner(String(err));
    }
}

function escapeHtml(value) {
    return String(value)
        .replaceAll('&', '&amp;')
        .replaceAll('<', '&lt;')
        .replaceAll('>', '&gt;')
        .replaceAll('"', '&quot;')
        .replaceAll("'", '&#39;');
}

function escapeJs(value) {
    return String(value)
        .replaceAll('\\', '\\\\')
        .replaceAll("'", "\\'");
}
</script>
{% endblock %}

{% extends "base.html" %}
{% block title %}Controls · Home Automation Server{% endblock %}

{% block header_subnav %}
{% if controls_devices %}
<div class="header-subnav">
    <div class="header-subnav-inner">
        {% for device in controls_devices %}
        <a
            href="{{ device.route }}"
            class="header-subnav-link{% if device.is_selected %} is-active{% endif %}"
            {% if device.is_selected %}aria-current="page"{% endif %}
        >
            {% if device.kind == 'apple_tv' %}
            {{ device.name }} (Apple TV)
            {% else %}
            {{ device.name }}
            {% endif %}
        </a>
        {% endfor %}
    </div>
</div>
{% endif %}
{% endblock %}

{% block content %}
<div class="page-header">
    <h1>Device Controls</h1>
</div>

<div id="controls-error-banner" class="notice hidden controls-error-banner">
    <span id="controls-error-banner-text"></span>
    <button type="button" class="btn btn-sm btn-secondary" onclick="clearErrorBanner()" aria-label="Dismiss error">✕</button>
</div>

<div
    id="controls-page-data"
    data-selected-device-id="{{ selected_device.id if selected_device else '' }}"
    data-selected-device-kind="{{ selected_device_kind or '' }}"
></div>

{% if not controls_devices %}
<div class="notice">No devices saved. <a href="/ui/devices">Add a device first.</a></div>
{% else %}
{% if selected_device %}
<section class="controls-provider-section">
    <div class="page-header controls-provider-header">
        <div>
            <h2>
                {% if selected_device_kind == 'apple_tv' %}
                Apple TV Remote
                {% else %}
                Samsung TV Remote
                {% endif %}
            </h2>
            <p class="subtitle">
                {% if selected_device_kind == 'apple_tv' %}
                Directional, playback, power, and installed-app controls for {{ selected_device.name }}.
                {% else %}
                Samsung key commands, power actions, and manual app launch for {{ selected_device.name }}.
                {% endif %}
            </p>
        </div>
    </div>

    <button
        type="button"
        id="automation-recorder-launcher"
        class="automation-recorder-launcher"
        onclick="toggleRecorderDrawer()"
        aria-expanded="false"
        aria-controls="automation-recorder"
    >
        Open Recorder
    </button>

    <aside id="automation-recorder" class="automation-recorder-drawer" aria-label="Automation recorder">
        <div class="automation-recorder">
            <div class="automation-recorder-header">
                <h3>Record automation</h3>
                <div class="automation-recorder-header-actions">
                    <span id="recording-indicator" class="badge">Idle</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="toggleRecorderDrawer()">Close</button>
                </div>
            </div>
            <p class="subtitle">Capture your button presses, keep realistic waits, then save as a sequence flow.</p>
            <div class="automation-recorder-controls">
                <label>Flow name
                    <input type="text" id="recording-flow-name" placeholder="Recorded flow" />
                </label>
                <label>Wait sensitivity
                    <input type="range" id="recording-wait-threshold" min="100" max="1500" step="50" value="300" oninput="updateRecorderSensitivityLabel()" />
                    <span id="recording-wait-threshold-value" class="mono">300 ms min gap</span>
                </label>
                <div class="controls-button-row">
                    <button type="button" class="btn btn-danger" id="recording-start-btn" onclick="startRecording()">Start Recording</button>
                    <button type="button" class="btn btn-secondary" id="recording-stop-btn" onclick="stopRecording()" disabled>Stop</button>
                    <button type="button" class="btn btn-secondary" id="recording-clear-btn" onclick="clearRecording()" disabled>Clear</button>
                    <button type="button" class="btn btn-success" id="recording-save-btn" onclick="saveRecordingAsFlow()" disabled>Save as Flow</button>
                </div>
                <div class="automation-recorder-log-anchor">
                    <button type="button" class="btn btn-sm btn-secondary" id="recording-log-toggle" onclick="toggleRecordingLog()">Live Log</button>
                    <div id="recording-log-popover" class="recording-log-popover hidden">
                        <div class="recording-log-header">
                            <strong>Live Log</strong>
                            <button type="button" class="btn btn-sm btn-secondary" onclick="toggleRecordingLog(false)">✕</button>
                        </div>
                        <div id="recording-log-entries" class="recording-log-entries"></div>
                    </div>
                </div>
            </div>
            <div id="recording-status" class="notice hidden"></div>
            <div id="recording-preview" class="notice hidden"></div>
        </div>
    </aside>

    <div id="recording-pulse-overlay" class="recording-pulse-overlay hidden" aria-live="polite">
        <span class="recording-pulse-dot" aria-hidden="true"></span>
        <span id="recording-pulse-text">REC</span>
    </div>

    {% if selected_device_kind == 'apple_tv' %}
    {% include "partials/controls_appletv.html" %}
    {% elif selected_device_kind == 'samsung_tv' %}
    {% include "partials/controls_samsung.html" %}
    {% endif %}
</section>
{% endif %}
{% endif %}
{% endblock %}

{% block scripts %}
<script>
const controlsPageData = document.getElementById('controls-page-data');
const selectedDeviceId = controlsPageData && controlsPageData.dataset.selectedDeviceId
    ? parseInt(controlsPageData.dataset.selectedDeviceId, 10)
    : null;
const selectedDeviceKind = controlsPageData && controlsPageData.dataset.selectedDeviceKind
    ? controlsPageData.dataset.selectedDeviceKind
    : null;

let errorBannerTimer = null;
let isRecording = false;
let recordingActions = [];
let lastRecordedAtMs = 0;
let recordingPulseTimer = null;
let isRecorderDrawerOpen = false;
let isRecordingLogOpen = false;
let recordingLogEntries = [];

function clearErrorBanner() {
    const banner = document.getElementById('controls-error-banner');
    const text = document.getElementById('controls-error-banner-text');
    if (!banner) return;
    if (errorBannerTimer) {
        clearTimeout(errorBannerTimer);
        errorBannerTimer = null;
    }
    banner.classList.add('hidden');
    if (text) {
        text.textContent = '';
    }
}

function showErrorBanner(message) {
    const banner = document.getElementById('controls-error-banner');
    const text = document.getElementById('controls-error-banner-text');
    if (!banner) return;
    if (errorBannerTimer) {
        clearTimeout(errorBannerTimer);
        errorBannerTimer = null;
    }
    banner.classList.remove('hidden');
    if (text) {
        text.textContent = '❌ ' + (message || 'Unexpected error');
    }
    errorBannerTimer = setTimeout(() => {
        clearErrorBanner();
    }, 6000);
}

document.addEventListener('DOMContentLoaded', () => {
    clearErrorBanner();
    clearNotice('control-status');
    clearNotice('atv-apps-status');
    clearNotice('samsung-status');
    clearNotice('samsung-app-status');
    if (selectedDeviceKind === 'apple_tv') {
        atvClearAppsResults();
        atvRefreshPower();
    }
    setRecorderDrawerOpen(false);
    toggleRecordingLog(false);
    updateRecorderSensitivityLabel();
    refreshRecorderUi();
});

function getRecordingWaitThresholdMs() {
    const raw = document.getElementById('recording-wait-threshold')?.value || '300';
    return Math.max(0, parseInt(raw, 10) || 300);
}

function pushRecordingLog(message) {
    recordingLogEntries.unshift({ ts: new Date(), message: String(message || '') });
    recordingLogEntries = recordingLogEntries.slice(0, 10);
    renderRecordingLog();
}

function renderRecordingLog() {
    const container = document.getElementById('recording-log-entries');
    if (!container) return;
    if (recordingLogEntries.length === 0) {
        container.innerHTML = '<div class="subtitle">No entries yet.</div>';
        return;
    }
    container.innerHTML = recordingLogEntries.map(entry => {
        const hh = String(entry.ts.getHours()).padStart(2, '0');
        const mm = String(entry.ts.getMinutes()).padStart(2, '0');
        const ss = String(entry.ts.getSeconds()).padStart(2, '0');
        return `<div class="recording-log-entry"><span class="mono">${hh}:${mm}:${ss}</span> ${escapeHtml(entry.message)}</div>`;
    }).join('');
}

function setRecorderDrawerOpen(open) {
    const drawer = document.getElementById('automation-recorder');
    const launcher = document.getElementById('automation-recorder-launcher');
    if (!drawer || !launcher) return;
    isRecorderDrawerOpen = !!open;
    drawer.classList.toggle('is-open', isRecorderDrawerOpen);
    launcher.textContent = isRecorderDrawerOpen ? 'Close Recorder' : 'Open Recorder';
    launcher.setAttribute('aria-expanded', isRecorderDrawerOpen ? 'true' : 'false');
}

function toggleRecorderDrawer(forceOpen) {
    if (typeof forceOpen === 'boolean') {
        setRecorderDrawerOpen(forceOpen);
        return;
    }
    setRecorderDrawerOpen(!isRecorderDrawerOpen);
}

function toggleRecordingLog(forceOpen) {
    const popover = document.getElementById('recording-log-popover');
    if (!popover) return;
    if (typeof forceOpen === 'boolean') {
        isRecordingLogOpen = forceOpen;
    } else {
        isRecordingLogOpen = !isRecordingLogOpen;
    }
    popover.classList.toggle('hidden', !isRecordingLogOpen);
    renderRecordingLog();
}

function updateRecorderSensitivityLabel() {
    const label = document.getElementById('recording-wait-threshold-value');
    if (label) label.textContent = `${getRecordingWaitThresholdMs()} ms min gap`;
}

function setRecordingStatus(message, ok = true) {
    const box = document.getElementById('recording-status');
    if (!box) return;
    if (!message) {
        box.classList.add('hidden');
        box.textContent = '';
        return;
    }
    box.classList.remove('hidden');
    box.textContent = (ok ? 'OK: ' : 'Error: ') + message;
    if (message) pushRecordingLog((ok ? 'OK ' : 'Error ') + message);
}

function setRecordingIndicator() {
    const indicator = document.getElementById('recording-indicator');
    if (!indicator) return;
    indicator.textContent = isRecording ? 'Recording' : 'Idle';
    indicator.style.borderColor = isRecording ? 'var(--danger)' : '';
    indicator.style.color = isRecording ? 'var(--danger)' : '';
}

function setRecordingPulseVisible(visible) {
    const overlay = document.getElementById('recording-pulse-overlay');
    if (!overlay) return;
    overlay.classList.toggle('hidden', !visible);
    if (!visible) overlay.classList.remove('is-flash');
}

function actionLabel(type, payload) {
    if (type === 'remote_command') return String(payload?.command || 'command');
    if (type === 'power') return payload?.turn_on ? 'power on' : 'power off';
    if (type === 'launch_app') return `launch ${payload?.bundle_id || payload?.app_id || 'app'}`;
    if (type === 'wait_seconds') return `wait ${payload?.seconds || '?'}s`;
    return type;
}

function flashRecordingPulse(type, payload) {
    if (!isRecording) return;
    const overlay = document.getElementById('recording-pulse-overlay');
    const text = document.getElementById('recording-pulse-text');
    if (!overlay || !text) return;

    text.textContent = `REC ${recordingActions.length}: ${actionLabel(type, payload)}`;
    overlay.classList.remove('hidden');
    overlay.classList.remove('is-flash');
    void overlay.offsetWidth;
    overlay.classList.add('is-flash');

    if (recordingPulseTimer) clearTimeout(recordingPulseTimer);
    recordingPulseTimer = setTimeout(() => {
        if (!isRecording) setRecordingPulseVisible(false);
    }, 700);
}

function refreshRecorderPreview() {
    const preview = document.getElementById('recording-preview');
    if (!preview) return;
    if (recordingActions.length === 0) {
        preview.classList.add('hidden');
        preview.textContent = '';
        return;
    }
    const lines = recordingActions.map((action, index) => {
        if (action.type === 'wait_seconds') return `${index + 1}. Wait ${action.payload.seconds}s`;
        if (action.type === 'remote_command') return `${index + 1}. ${action.payload.command}`;
        if (action.type === 'power') return `${index + 1}. Power ${action.payload.turn_on ? 'On' : 'Off'}`;
        if (action.type === 'launch_app') return `${index + 1}. Launch ${action.payload.bundle_id || action.payload.app_id || '?'}`;
        return `${index + 1}. ${action.type}`;
    });
    preview.classList.remove('hidden');
    preview.textContent = lines.join('  |  ');
}

function refreshRecorderUi() {
    const startBtn = document.getElementById('recording-start-btn');
    const stopBtn = document.getElementById('recording-stop-btn');
    const clearBtn = document.getElementById('recording-clear-btn');
    const saveBtn = document.getElementById('recording-save-btn');
    if (startBtn) startBtn.disabled = isRecording;
    if (stopBtn) stopBtn.disabled = !isRecording;
    if (clearBtn) clearBtn.disabled = isRecording || recordingActions.length === 0;
    if (saveBtn) saveBtn.disabled = isRecording || recordingActions.length === 0;
    setRecordingIndicator();
    setRecordingPulseVisible(isRecording);
    if (isRecording) {
        const pulseText = document.getElementById('recording-pulse-text');
        if (pulseText) pulseText.textContent = `REC ${recordingActions.length}`;
    }
    refreshRecorderPreview();
}

function startRecording() {
    clearErrorBanner();
    setRecorderDrawerOpen(true);
    recordingActions = [];
    recordingLogEntries = [];
    renderRecordingLog();
    lastRecordedAtMs = 0;
    isRecording = true;
    setRecordingStatus('Recording started. Use remote controls to capture a flow.');
    refreshRecorderUi();
}

function stopRecording() {
    isRecording = false;
    setRecordingStatus(`Recording stopped. Captured ${recordingActions.length} step(s).`);
    refreshRecorderUi();
}

function clearRecording() {
    recordingActions = [];
    lastRecordedAtMs = 0;
    setRecordingStatus('Recording cleared.');
    refreshRecorderUi();
}

function maybeRecordWait(nowMs) {
    if (!lastRecordedAtMs) return;
    const gapMs = nowMs - lastRecordedAtMs;
    const thresholdMs = getRecordingWaitThresholdMs();
    if (gapMs < thresholdMs) return;
    const seconds = Math.max(0.1, Math.round((gapMs / 1000) * 10) / 10);
    recordingActions.push({ type: 'wait_seconds', payload: { seconds } });
    pushRecordingLog(`Auto wait inserted: ${seconds}s`);
}

function recordAction(type, payload) {
    if (!isRecording) return;
    const nowMs = Date.now();
    maybeRecordWait(nowMs);
    recordingActions.push({ type, payload: payload || {} });
    flashRecordingPulse(type, payload);
    pushRecordingLog(`Captured: ${actionLabel(type, payload)}`);
    lastRecordedAtMs = nowMs;
    setRecordingStatus(`Recorded ${recordingActions.length} step(s).`);
    refreshRecorderUi();
}

async function saveRecordingAsFlow() {
    if (recordingActions.length === 0) {
        setRecordingStatus('Nothing recorded yet.', false);
        return;
    }
    if (!Number.isInteger(selectedDeviceId) || !selectedDeviceKind) {
        setRecordingStatus('No selected device found for saving this flow.', false);
        return;
    }

    const flowNameInput = document.getElementById('recording-flow-name');
    const flowName = (flowNameInput?.value || '').trim() || `Recorded ${selectedDeviceKind} flow ${new Date().toLocaleString()}`;
    const payload = {
        name: flowName,
        device_kind: selectedDeviceKind,
        device_id: selectedDeviceId,
        trigger_type: 'manual',
        trigger_payload: '{}',
        action_type: 'sequence',
        action_payload: JSON.stringify({ actions: recordingActions }),
    };

    try {
        clearErrorBanner();
        const res = await fetch('/automations/', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
        });
        const data = await res.json().catch(() => ({}));
        if (!res.ok) {
            const msg = data.detail || 'Failed to save recorded automation';
            setRecordingStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        setRecordingStatus(`Saved flow "${flowName}" with ${recordingActions.length} step(s).`);
        isRecording = false;
        toggleRecordingLog(false);
        refreshRecorderUi();
    } catch (err) {
        const msg = String(err);
        setRecordingStatus(msg, false);
        showErrorBanner(msg);
    }
}

function requireSelectedDeviceId(label) {
    if (!Number.isInteger(selectedDeviceId)) {
        throw new Error(`Select a ${label} device first`);
    }
    return selectedDeviceId;
}

function setNotice(elementId, message, ok = true) {
    const box = document.getElementById(elementId);
    if (!box) return;
    box.classList.remove('hidden');
    box.textContent = (ok ? '✅ ' : '❌ ') + message;
}

function clearNotice(elementId) {
    const box = document.getElementById(elementId);
    if (!box) return;
    box.classList.add('hidden');
    box.textContent = '';
}

function clearAppsResults(resultsId, statusId) {
    const results = document.getElementById(resultsId);
    const status = document.getElementById(statusId);
    if (results) {
        results.classList.add('hidden');
        results.innerHTML = '';
    }
    if (status) {
        status.classList.add('hidden');
        status.textContent = '';
    }
}

function setPowerStateBadge(badgeId, state, ok = true) {
    const badge = document.getElementById(badgeId);
    if (!badge) return;

    const normalized = String(state || 'unknown').toLowerCase();
    badge.textContent = normalized.charAt(0).toUpperCase() + normalized.slice(1);

    // Reset inline styles so state transitions don't stack
    badge.style.borderColor = '';
    badge.style.color = '';

    if (!ok) {
        badge.textContent = 'Unavailable';
        badge.style.borderColor = '#f87171';
        badge.style.color = '#f87171';
        return;
    }

    if (normalized === 'on') {
        badge.style.borderColor = '#34d399';
        badge.style.color = '#34d399';
    } else if (normalized === 'off') {
        badge.style.borderColor = '#f87171';
        badge.style.color = '#f87171';
    } else {
        badge.style.borderColor = '#fbbf24';
        badge.style.color = '#fbbf24';
    }
}

function atvSelectedDeviceId() {
    return requireSelectedDeviceId('Apple TV');
}

function atvSetStatus(message, ok = true) {
    setNotice('control-status', message, ok);
}

function atvSetAppsStatus(message, ok = true) {
    setNotice('atv-apps-status', message, ok);
}

function atvClearAppsResults() {
    clearAppsResults('atv-apps-results', 'atv-apps-status');
}

async function atvRefreshPower() {
    try {
        clearErrorBanner();
        const res = await fetch(`/controls/power-state/${atvSelectedDeviceId()}`);
        const data = await res.json();
        if (!res.ok) {
            setPowerStateBadge('atv-power-badge', 'unknown', false);
            if (res.status !== 501) {
                const msg = data.detail || 'Failed to get power state';
                atvSetStatus(msg, false);
                showErrorBanner(msg);
            } else {
                const msg = data.detail || 'Power state not supported on this device';
                atvSetStatus(msg, false);
            }
            return;
        }
        setPowerStateBadge('atv-power-badge', data.power_state, true);
    } catch (err) {
        setPowerStateBadge('atv-power-badge', 'unknown', false);
        const msg = String(err);
        atvSetStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function atvCmd(command) {
    try {
        clearErrorBanner();
        const res = await fetch('/controls/appletv/command', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: atvSelectedDeviceId(), command })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to send command';
            atvSetStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        atvSetStatus(`Sent command: ${command}`);
        recordAction('remote_command', { command });
    } catch (err) {
        const msg = String(err);
        atvSetStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function atvPower(turnOn) {
    try {
        clearErrorBanner();
        const res = await fetch('/controls/appletv/power', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: atvSelectedDeviceId(), turn_on: turnOn })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to change power state';
            atvSetStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        atvSetStatus(`Power ${turnOn ? 'on' : 'off'} command sent`);
        recordAction('power', { turn_on: turnOn });
        setTimeout(atvRefreshPower, 1200);
    } catch (err) {
        const msg = String(err);
        atvSetStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function atvFetchApps() {
    const results = document.getElementById('atv-apps-results');
    if (!results) return;
    results.classList.remove('hidden');
    results.innerHTML = '⏳ Loading installed apps…';

    try {
        clearErrorBanner();
        const res = await fetch(`/apps/list/${atvSelectedDeviceId()}`);
        const data = await res.json();
        if (!res.ok) {
            results.innerHTML = '';
            if (res.status === 501) {
                results.classList.remove('hidden');
                results.innerHTML = `
                    <div class="notice">
                        This device does not support installed app listing via pyatv.<br/>
                        You can still launch an app manually using a bundle ID above.
                    </div>
                `;
            }
            const msg = data.detail || 'Failed to list apps';
            atvSetAppsStatus(msg, false);
            if (res.status !== 501) {
                showErrorBanner(msg);
            }
            return;
        }

        if (data.length === 0) {
            results.innerHTML = '<div class="notice">No apps returned by the device.</div>';
            atvSetAppsStatus('App list loaded');
            return;
        }

        results.innerHTML = `
            <table class="data-table">
                <thead>
                    <tr>
                        <th>App Name</th>
                        <th>Bundle ID</th>
                        <th>Action</th>
                    </tr>
                </thead>
                <tbody>
                    ${data.map(app => `
                        <tr>
                            <td>${escapeHtml(app.name || 'Unknown')}</td>
                            <td class="mono">${escapeHtml(app.bundle_id || '')}</td>
                            <td>
                                <button class="btn btn-sm btn-success" onclick="atvLaunchApp('${escapeJs(app.bundle_id || '')}')">Launch</button>
                            </td>
                        </tr>
                    `).join('')}
                </tbody>
            </table>
        `;
        atvSetAppsStatus(`Loaded ${data.length} app(s)`);
    } catch (err) {
        results.innerHTML = '';
        const msg = String(err);
        atvSetAppsStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function atvLaunchApp(bundleId) {
    try {
        clearErrorBanner();
        const res = await fetch('/apps/appletv/launch', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: atvSelectedDeviceId(), bundle_id: bundleId })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to launch app';
            atvSetAppsStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        atvSetAppsStatus(`Launched ${bundleId}`);
        recordAction('launch_app', { bundle_id: bundleId });
    } catch (err) {
        const msg = String(err);
        atvSetAppsStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function atvLaunchBundle(event) {
    event.preventDefault();
    const bundleId = document.getElementById('atv-bundle-id').value.trim();
    if (!bundleId) {
        const msg = 'Enter a bundle ID first';
        atvSetAppsStatus(msg, false);
        showErrorBanner(msg);
        return;
    }
    await atvLaunchApp(bundleId);
}

function samsungSelectedDeviceId() {
    return requireSelectedDeviceId('Samsung TV');
}

function samsungSetStatus(message, ok = true) {
    setNotice('samsung-status', message, ok);
}

function samsungSetAppStatus(message, ok = true) {
    setNotice('samsung-app-status', message, ok);
}


async function samsungCmd(command) {
    try {
        clearErrorBanner();
        const res = await fetch('/controls/samsung/command', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: samsungSelectedDeviceId(), command })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to send Samsung command';
            samsungSetStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        samsungSetStatus(`Sent command: ${command}`);
        recordAction('remote_command', { command });
    } catch (err) {
        const msg = String(err);
        samsungSetStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function samsungPower(turnOn) {
    try {
        clearErrorBanner();
        const res = await fetch('/controls/samsung/power', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: samsungSelectedDeviceId(), turn_on: turnOn })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to change Samsung power state';
            samsungSetStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        samsungSetStatus(`Power ${turnOn ? 'on' : 'off'} command sent`);
        recordAction('power', { turn_on: turnOn });
    } catch (err) {
        const msg = String(err);
        samsungSetStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function samsungLaunchApp(event) {
    event.preventDefault();
    const appId = document.getElementById('samsung-app-id').value.trim();
    if (!appId) {
        const msg = 'Enter a Samsung app ID first';
        samsungSetAppStatus(msg, false);
        showErrorBanner(msg);
        return;
    }

    try {
        clearErrorBanner();
        const res = await fetch('/apps/samsung/launch', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ device_id: samsungSelectedDeviceId(), app_id: appId })
        });
        const data = await res.json();
        if (!res.ok) {
            const msg = data.detail || 'Failed to launch Samsung app';
            samsungSetAppStatus(msg, false);
            showErrorBanner(msg);
            return;
        }
        samsungSetAppStatus(`Launched ${appId}`);
        recordAction('launch_app', { app_id: appId });
    } catch (err) {
        const msg = String(err);
        samsungSetAppStatus(msg, false);
        showErrorBanner(msg);
    }
}

async function samsungFetchSources() {
    try {
        clearErrorBanner();
        const res = await fetch(`/controls/samsung/sources/${samsungSelectedDeviceId()}`);
        const data = await res.json();
        if (!res.ok) {
            showErrorBanner(data.detail || 'Failed to fetch sources');
            return;
        }
        // Re-render the companion grid with the authoritative input list from the server
        const grid = document.getElementById('samsung-inputs-grid');
        if (!grid || !data.inputs) return;
        grid.innerHTML = data.inputs.map(input => `
            <button class="samsung-input-companion-btn" onclick="samsungCmd('${escapeJs(input.command)}')">
                ${escapeHtml(input.icon)} ${escapeHtml(input.label)}
            </button>
        `).join('') + `
            <button class="samsung-input-companion-btn" onclick="samsungCmd('source')">⬡ Source Menu</button>
        `;
    } catch (err) {
        showErrorBanner(String(err));
    }
}

function escapeHtml(value) {
    return String(value)
        .replaceAll('&', '&amp;')
        .replaceAll('<', '&lt;')
        .replaceAll('>', '&gt;')
        .replaceAll('"', '&quot;')
        .replaceAll("'", '&#39;');
}

function escapeJs(value) {
    return String(value)
        .replaceAll('\\', '\\\\')
        .replaceAll("'", "\\'");
}
</script>
{% endblock %}
